28	#include "bostree.h"
29	#include <assert.h>
30	#include <stddef.h>
31	#include <stdlib.h>
32	#include <string.h>
33	
34	/* Tree structure */
35	struct _BOSTree {
36		BOSNode *root_node;
37	
38		BOSTree_cmp_function cmp_function;
39		BOSTree_free_function free_function;
40	};
41	
42	/* Local helper functions */
43	static int _imax(const int i1, const int i2) {
44		return i1 > i2 ? i1 : i2;
45	}
46	
47	static int _bostree_balance(BOSNode *node) {
48		const int left_depth = node->left_child_node ? node->left_child_node->depth + 1 : 0;
49		const int right_depth = node->right_child_node ? node->right_child_node->depth + 1 : 0;
50		return right_depth - left_depth;
51	}
52	
53	static BOSNode *_bostree_rotate_right(BOSTree *tree, BOSNode *P) {
54		// Rotate right:
55		//
56		//      P                     L
57		//  L        R     -->    c1      P
58		//c1 c2                        c2     R
59		//
60		BOSNode *L = P->left_child_node;
61	
62		if(P->parent_node) {
63			if(P->parent_node->left_child_node == P) {
64				P->parent_node->left_child_node = L;
65			}
66			else {
67				P->parent_node->right_child_node = L;
68			}
69		}
70		else {
71			tree->root_node = L;
72		}
73	
74		L->parent_node = P->parent_node;
75	
76		P->left_child_node = L->right_child_node;
77		P->left_child_count = L->right_child_count;
78		if(P->left_child_node) {
79			P->left_child_node->parent_node = P;
80		}
81		P->depth = _imax(P->left_child_node ? 1 + P->left_child_node->depth : 0, P->right_child_node ? 1 + P->right_child_node->depth : 0);
82		P->parent_node = L;
83	
84		L->right_child_node = P;
85		P->parent_node = L;
86		L->right_child_count = P->left_child_count + P->right_child_count + 1;
87		L->depth = _imax(L->left_child_node ? 1 + L->left_child_node->depth : 0, L->right_child_node ? 1 + L->right_child_node->depth : 0);
88	
89		return L;
90	}
91	
92	static BOSNode *_bostree_rotate_left(BOSTree *tree, BOSNode *P) {
93		// Rotate left:
94		//
95		//      P                     R
96		//  L        R     -->    P      c2
97		//         c1 c2        L  c1
98		//
99		BOSNode *R = P->right_child_node;
100	
101		if(P->parent_node) {
102			if(P->parent_node->left_child_node == P) {
103				P->parent_node->left_child_node = R;
104			}
105			else {
106				P->parent_node->right_child_node = R;
107			}
108		}
109		else {
110			tree->root_node = R;
111		}
112	
113		R->parent_node = P->parent_node;
114	
115		P->right_child_node = R->left_child_node;
116		P->right_child_count = R->left_child_count;
117		if(P->right_child_node) {
118			P->right_child_node->parent_node = P;
119		}
120		P->depth = _imax(P->left_child_node ? 1 + P->left_child_node->depth : 0, P->right_child_node ? 1 + P->right_child_node->depth : 0);
121		P->parent_node = R;
122	
123		R->left_child_node = P;
124		P->parent_node = R;
125		R->left_child_count = P->left_child_count + P->right_child_count + 1;
126		R->depth = _imax(R->left_child_node ? 1 + R->left_child_node->depth : 0, R->right_child_node ? 1 + R->right_child_node->depth : 0);
127	
128		return R;
129	}
130	
131	
132	/* API implementation */
133	BOSTree *bostree_new(BOSTree_cmp_function cmp_function, BOSTree_free_function free_function) {
134		BOSTree *new_tree = malloc(sizeof(BOSTree));
135		new_tree->root_node = NULL;
136		new_tree->cmp_function = cmp_function;
137		new_tree->free_function = free_function;
138		return new_tree;
139	}
140	
141	void bostree_destroy(BOSTree *tree) {
142		// Walk the tree and unref all nodes
143		BOSNode *node = tree->root_node;
144		while(node) {
145			// The order should not really matter, but use post-order traversal here.
146			while(node->left_child_node) {
147				node = node->left_child_node;
148			}
149	
150			if(node->right_child_node) {
151				node = node->right_child_node;
152				continue;
153			}
154	
155			// At this point, we can be sure that this node has no child nodes.
156			// So it is safe to remove it.
157			BOSNode *next = node->parent_node;
158			if(next) {
159				if(next->left_child_node == node) {
160					next->left_child_node = NULL;
161				}
162				else {
163					next->right_child_node = NULL;
164				}
165			}
166			bostree_node_weak_unref(tree, node);
167			node = next;
168		}
169	
170		free(tree);
171	}
172	
173	unsigned int bostree_node_count(BOSTree *tree) {
174		return tree->root_node ? tree->root_node->left_child_count + tree->root_node->right_child_count + 1 : 0;
175	}
176	
177	BOSNode *bostree_insert(BOSTree *tree, void *key, void *data) {
178		BOSNode **node = &tree->root_node;
179		BOSNode *parent_node = NULL;
180	
181		// Find tree position to insert new node
182		while(*node) {
183			parent_node = *node;
184			int cmp = tree->cmp_function(key, (*node)->key);
185			if(cmp < 0) {
186				(*node)->left_child_count++;
187				node = &(*node)->left_child_node;
188			}
189			else {
190				(*node)->right_child_count++;
191				node = &(*node)->right_child_node;
192			}
193		}
194	
195		// Create new node
196		BOSNode *new_node = malloc(sizeof(BOSNode));
197		memset(new_node, 0, sizeof(BOSNode));
198		new_node->key = key;
199		new_node->data = data;
200		new_node->weak_ref_count = 1;
201		new_node->weak_ref_node_valid = 1;
202		new_node->parent_node = parent_node;
203	
204		*node = new_node;
205	
206		if(!parent_node) {
207			// Simple case, this is the first node.
208			tree->root_node = new_node;
209			return new_node;
210		}
211	
212		// Check if the depth changed with the new node:
213		// It does only change if this is the first child of the parent
214		if(!!parent_node->left_child_node ^ !!parent_node->right_child_node) {
215			// Bubble the information up the tree
216			parent_node->depth++;
217			while(parent_node->parent_node) {
218				// Assign new depth
219				parent_node = parent_node->parent_node;
220	
221				unsigned int new_left_depth  = parent_node->left_child_node ? parent_node->left_child_node->depth + 1 : 0;
222				unsigned int new_right_depth = parent_node->right_child_node ? parent_node->right_child_node->depth + 1 : 0;
223	
224				unsigned int max_depth = _imax(new_left_depth, new_right_depth);
225	
226				if(parent_node->depth != max_depth) {
227					parent_node->depth = max_depth;
228				}
229				else {
230					// We can break here, because if the depth did not change
231					// at this level, it won't have further up either.
232					break;
233				}
234	
235				// Check if this node violates the AVL property, that is, that the
236				// depths differ by no more than 1.
237				if(new_left_depth - 2 == new_right_depth) {
238					// Handle left-right case
239					if(_bostree_balance(parent_node->left_child_node) > 0) {
240						_bostree_rotate_left(tree, parent_node->left_child_node);
241					}
242	
243					// Left is two levels deeper than right. Rotate right.
244					parent_node = _bostree_rotate_right(tree, parent_node);
245				}
246				else if(new_left_depth + 2 == new_right_depth) {
247					// Handle right-left case
248					if(_bostree_balance(parent_node->right_child_node) < 0) {
249						_bostree_rotate_right(tree, parent_node->right_child_node);
250					}
251	
252					// Right is two levels deeper than left. Rotate left.
253					parent_node = _bostree_rotate_left(tree, parent_node);
254				}
255			}
256		}
257	
258		return new_node;
259	}
260	
261	void bostree_remove(BOSTree *tree, BOSNode *node) {
262		BOSNode *bubble_up = NULL;
263	
264		// If this node has children on both sides, bubble one of it upwards
265		// and rotate within the subtrees.
266		if(node->left_child_node && node->right_child_node) {
267			BOSNode *candidate = NULL;
268			BOSNode *lost_child = NULL;
269			if(node->left_child_node->depth >= node->right_child_node->depth) {
270				// Left branch is deeper than right branch, might be a good idea to
271				// bubble from this side to maintain the AVL property with increased
272				// likelihood.
273				node->left_child_count--;
274				candidate = node->left_child_node;
275				while(candidate->right_child_node) {
276					candidate->right_child_count--;
277					candidate = candidate->right_child_node;
278				}
279				lost_child = candidate->left_child_node;
280			}
281			else {
282				node->right_child_count--;
283				candidate = node->right_child_node;
284				while(candidate->left_child_node) {
285					candidate->left_child_count--;
286					candidate = candidate->left_child_node;
287				}
288				lost_child = candidate->right_child_node;
289			}
290	
291			BOSNode *bubble_start = candidate->parent_node;
292			if(bubble_start->left_child_node == candidate) {
293				bubble_start->left_child_node = lost_child;
294			}
295			else {
296				bubble_start->right_child_node = lost_child;
297			}
298			if(lost_child) {
299				lost_child->parent_node = bubble_start;
300			}
301	
302			// We will later rebalance upwards from bubble_start up to candidate.
303			// But first, anchor candidate into the place where "node" used to be.
304	
305			if(node->parent_node) {
306				if(node->parent_node->left_child_node == node) {
307					node->parent_node->left_child_node = candidate;
308				}
309				else {
310					node->parent_node->right_child_node = candidate;
311				}
312			}
313			else {
314				tree->root_node = candidate;
315			}
316			candidate->parent_node = node->parent_node;
317	
318			candidate->left_child_node = node->left_child_node;
319			candidate->left_child_count = node->left_child_count;
320			candidate->right_child_node = node->right_child_node;
321			candidate->right_child_count = node->right_child_count;
322	
323			if(candidate->left_child_node) {
324				candidate->left_child_node->parent_node = candidate;
325			}
326	
327			if(candidate->right_child_node) {
328				candidate->right_child_node->parent_node = candidate;
329			}
330	
331			// From here on, node is out of the game.
332			// Rebalance up to candidate.
333	
334			if(bubble_start != node) {
335				while(bubble_start != candidate) {
336					bubble_start->depth = _imax((bubble_start->left_child_node ? bubble_start->left_child_node->depth + 1 : 0),
337						(bubble_start->right_child_node ? bubble_start->right_child_node->depth + 1 : 0));
338					int balance = _bostree_balance(bubble_start);
339					if(balance > 1) {
340						// Rotate left. Check for right-left case before.
341						if(_bostree_balance(bubble_start->right_child_node) < 0) {
342							_bostree_rotate_right(tree, bubble_start->right_child_node);
343						}
344						bubble_start = _bostree_rotate_left(tree, bubble_start);
345					}
346					else if(balance < -1) {
347						// Rotate right. Check for left-right case before.
348						if(_bostree_balance(bubble_start->left_child_node) > 0) {
349							_bostree_rotate_left(tree, bubble_start->left_child_node);
350						}
351						bubble_start = _bostree_rotate_right(tree, bubble_start);
352					}
353					bubble_start = bubble_start->parent_node;
354				}
355			}
356	
357			// Fixup candidate's depth
358			candidate->depth = _imax((candidate->left_child_node ? candidate->left_child_node->depth + 1 : 0),
359				(candidate->right_child_node ? candidate->right_child_node->depth + 1 : 0));
360	
361			// We'll have to fixup child counts and depths up to the root, do that
362			// later.
363			bubble_up = candidate->parent_node;
364	
365			// Fix immediate parent node child count here.
366			if(bubble_up) {
367				if(bubble_up->left_child_node == candidate) {
368					bubble_up->left_child_count--;
369				}
370				else {
371					bubble_up->right_child_count--;
372				}
373			}
374		}
375		else {
376			// If this node has children on one side only, removing it is much simpler.
377			if(!node->parent_node) {
378				// Simple case: Node _was_ the old root.
379				if(node->left_child_node) {
380					tree->root_node = node->left_child_node;
381					if(node->left_child_node) {
382						node->left_child_node->parent_node = NULL;
383					}
384				}
385				else {
386					tree->root_node = node->right_child_node;
387					if(node->right_child_node) {
388						node->right_child_node->parent_node = NULL;
389					}
390				}
391	
392				// No rebalancing to do
393				bubble_up = NULL;
394			}
395			else {
396				BOSNode *candidate = node->left_child_node;
397				int candidate_count = node->left_child_count;
398				if(node->right_child_node) {
399					candidate = node->right_child_node;
400					candidate_count = node->right_child_count;
401				}
402	
403				if(node->parent_node->left_child_node == node) {
404					node->parent_node->left_child_node = candidate;
405					node->parent_node->left_child_count = candidate_count;
406				}
407				else {
408					node->parent_node->right_child_node = candidate;
409					node->parent_node->right_child_count = candidate_count;
410				}
411	
412				if(candidate) {
413					candidate->parent_node = node->parent_node;
414				}
415	
416				// Again, from here on, the original node is out of the game.
417				// Rebalance up to the root.
418				bubble_up = node->parent_node;
419			}
420		}
421	
422		// At this point, everything below and including bubble_start is
423		// balanced, and we have to look further up.
424	
425		char bubbling_finished = 0;
426		while(bubble_up) {
427			if(!bubbling_finished) {
428				// Calculate updated depth for bubble_up
429				unsigned int left_depth = bubble_up->left_child_node ? bubble_up->left_child_node->depth + 1 : 0;
430				unsigned int right_depth = bubble_up->right_child_node ? bubble_up->right_child_node->depth + 1 : 0;
431				unsigned int new_depth = _imax(left_depth, right_depth);
432				char depth_changed = (new_depth != bubble_up->depth);
433				bubble_up->depth = new_depth;
434	
435				// Rebalance bubble_up
436				// Not necessary for the first node, but calling _bostree_balance once
437				// isn't that much overhead.
438				int balance = _bostree_balance(bubble_up);
439				if(balance < -1) {
440					if(_bostree_balance(bubble_up->left_child_node) > 0) {
441						_bostree_rotate_left(tree, bubble_up->left_child_node);
442					}
443					bubble_up = _bostree_rotate_right(tree, bubble_up);
444				}
445				else if(balance > 1) {
446					if(_bostree_balance(bubble_up->right_child_node) < 0) {
447						_bostree_rotate_right(tree, bubble_up->right_child_node);
448					}
449					bubble_up = _bostree_rotate_left(tree, bubble_up);
450				}
451				else {
452					if(!depth_changed) {
453						// If we neither had to rotate nor to change the depth,
454						// then we are obviously finished.  Only update child
455						// counts from here on.
456						bubbling_finished = 1;
457					}
458				}
459			}
460	
461			if(bubble_up->parent_node) {
462				if(bubble_up->parent_node->left_child_node == bubble_up) {
463					bubble_up->parent_node->left_child_count--;
464				}
465				else {
466					bubble_up->parent_node->right_child_count--;
467				}
468			}
469			bubble_up = bubble_up->parent_node;
470		}
471	
472		node->weak_ref_node_valid = 0;
473		bostree_node_weak_unref(tree, node);
474	}
