use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    /// The root node of the tree.
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    /// The key comparison function.
    pub cmp_function: BOSTreeCmpFunction,
    /// The optional free function for node data.
    pub free_function: Option<BOSTreeFreeFunction>,
}

/// The node structure.
#[derive(Debug)]
pub struct BOSNode {
    /// Number of nodes in the left subtree.
    pub left_child_count: u32,
    /// Number of nodes in the right subtree.
    pub right_child_count: u32,
    /// Cached depth of the node.
    pub depth: u32,
    /// Left child node.
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Right child node.
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Parent node (using a weak reference to avoid cycles).
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    /// The key for this node.
    pub key: String,
    /// The associated data.
    pub data: Option<String>,
    /// Internal weak reference counter.
    pub weak_ref_count: u8,
    /// Validity flag for the weak reference.
    pub weak_ref_node_valid: u8,
}

/// Type alias for a key comparison function.
/// Should return a positive value if `b` is larger than `a`,
/// a negative value if `a` is larger, and zero if equal.
pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;

/// Type alias for a free function which will be called on nodes
/// that are removed.
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

/// Helper function to compute max of two integers.
#[inline]
fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 {
        i1
    } else {
        i2
    }
}

/// Helper function to get the depth of a node's child.
#[inline]
fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
}

/// Compute the balance factor of a node (right depth - left depth).
fn compute_balance(node: &BOSNode) -> i32 {
    let left_depth = child_depth(&node.left_child_node);
    let right_depth = child_depth(&node.right_child_node);
    right_depth - left_depth
}

/// Rotate right and return the new root of this subtree.
fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // Rotate right:
    //
    //      P                     L
    //  L        R     -->    c1      P
    //c1 c2                        c2     R
    //
    let mut p_borrow = p.borrow_mut();
    let l = p_borrow.left_child_node.take();

    if l.is_none() {
        return p.clone();
    }

    let l = l.unwrap();
    let l_borrow = l.borrow();
    let l_right = l_borrow.right_child_node.clone();
    let l_right_count = l_borrow.right_child_count;
    let p_parent = p_borrow.parent_node.clone();
    drop(l_borrow);
    drop(p_borrow);

    let lRc = l.clone();
    let pRc = p.clone();

    // Update parent relationship
    if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_strong) = p_parent_weak.upgrade() {
            let mut parent_borrow = p_parent_strong.borrow_mut();
            if parent_borrow.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &pRc)) {
                parent_borrow.left_child_node = Some(lRc.clone());
            } else {
                parent_borrow.right_child_node = Some(lRc.clone());
            }
        }
    } else {
        tree.root_node = Some(lRc.clone());
    }

    {
        let mut l_mut = lRc.borrow_mut();
        l_mut.parent_node = p_parent;
    }

    // P's left becomes L's right
    {
        let mut p_mut = pRc.borrow_mut();
        p_mut.left_child_node = l_right;
        p_mut.left_child_count = l_right_count;

        if p_mut.left_child_node.is_some() {
            if let Some(ref left_child) = p_mut.left_child_node {
                let mut left_mut = left_child.borrow_mut();
                left_mut.parent_node = Some(Rc::downgrade(&pRc));
            }
        }

        let left_depth = child_depth(&p_mut.left_child_node);
        let right_depth = child_depth(&p_mut.right_child_node);
        p_mut.depth = imax(left_depth, right_depth) as u32;
        p_mut.parent_node = Some(Rc::downgrade(&lRc));
    }

    // L's right becomes P
    {
        let mut l_mut = lRc.borrow_mut();
        l_mut.right_child_node = Some(pRc.clone());
        let mut p_mut = pRc.borrow_mut();
        p_mut.parent_node = Some(Rc::downgrade(&lRc));

        l_mut.right_child_count = p_mut.left_child_count + p_mut.right_child_count + 1;

        let left_depth = child_depth(&l_mut.left_child_node);
        let right_depth = child_depth(&l_mut.right_child_node);
        l_mut.depth = imax(left_depth, right_depth) as u32;
    }

    lRc
}

