        r_mut.left_child_count = p_rc.borrow().left_child_count + p_rc.borrow().right_child_count + 1;

        let left_depth = child_depth(&r_mut.left_child_node);
        let right_depth = child_depth(&r_mut.right_child_node);
        r_mut.depth = imax(left_depth, right_depth) as u32;
    }

    r_rc
}

impl BOSTree {
    /// Create a new tree with a mandatory comparison function and an optional free function.
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    /// Return the number of nodes in the tree.
    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            let root_borrow = root.borrow();
            root_borrow.left_child_count + root_borrow.right_child_count + 1
        } else {
            0
        }
    }

    /// Insert a new member into the tree and return the associated node.
    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        // Simple case: empty tree
        if self.root_node.is_none() {
            let new_node = Rc::new(RefCell::new(BOSNode {
                left_child_count: 0,
                right_child_count: 0,
                depth: 1,
                left_child_node: None,
                right_child_node: None,
                parent_node: None,
                key,
                data,
                weak_ref_count: 1,
                weak_ref_node_valid: 1,
            }));
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        // Find the insertion point and track the path
        let mut path: Vec<Rc<RefCell<BOSNode>>> = Vec::new();
        let mut current = self.root_node.clone();

        loop {
            let current_rc = current.unwrap();
            let cmp = (self.cmp_function)(&key, &current_rc.borrow().key);

            {
                let mut curr_mut = current_rc.borrow_mut();
                if cmp < 0 {
                    curr_mut.left_child_count += 1;
                    if curr_mut.left_child_node.is_some() {
                        path.push(current_rc.clone());
                        current = curr_mut.left_child_node.clone();
                        continue;
                    } else {
                        curr_mut.left_child_node = Some(Rc::new(RefCell::new(BOSNode {
                            left_child_count: 0,
                            right_child_count: 0,
                            depth: 1,
                            left_child_node: None,
                            right_child_node: None,
                            parent_node: Some(Rc::downgrade(&current_rc)),
                            key,
                            data,
                            weak_ref_count: 1,
                            weak_ref_node_valid: 1,
                        }));
                        break;
                    }
                } else {
                    curr_mut.right_child_count += 1;
                    if curr_mut.right_child_node.is_some() {
                        path.push(current_rc.clone());
                        current = curr_mut.right_child_node.clone();
                        continue;
                    } else {
                        curr_mut.right_child_node = Some(Rc::new(RefCell::new(BOSNode {
                            left_child_count: 0,
                            right_child_count: 0,
                            depth: 1,
                            left_child_node: None,
                            right_child_node: None,
                            parent_node: Some(Rc::downgrade(&current_rc)),
                            key,
                            data,
                            weak_ref_count: 1,
                            weak_ref_node_valid: 1,
                        }));
                        break;
                    }
                }
            }
        }

        // Get the newly inserted node
        let new_node = {
            let last = path.last().unwrap();
            let last_borrow = last.borrow();
            if last_borrow.left_child_node.is_some() {
                last_borrow.left_child_node.clone().unwrap()
            } else {
                last_borrow.right_child_node.clone().unwrap()
            }
        };

        // Rebalance up the tree
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = Some(path.last().unwrap().clone());
        while let Some(ref current_parent) = bubble_up {
            let parent_weak = Rc::downgrade(current_parent);

            // Update depth
            let mut curr_mut = current_parent.borrow_mut();
            let new_left_depth = child_depth(&curr_mut.left_child_node);
            let new_right_depth = child_depth(&curr_mut.right_child_node);
            let max_depth = imax(new_left_depth, new_right_depth);

            let depth_changed = curr_mut.depth != max_depth as u32;
            if depth_changed {
                curr_mut.depth = max_depth as u32;
            } else {
                break;
            }

            // Check AVL property
            if new_left_depth - 2 == new_right_depth {
                // Left-right case
                let left_child = curr_mut.left_child_node.as_ref().unwrap().clone();
                let left_balance = compute_balance(&left_child.borrow());
                drop(curr_mut);

                if left_balance > 0 {
                    rotate_left(self, &left_child);
                }

                let new_root = rotate_right(self, &current_parent);
                bubble_up = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                continue;
            } else if new_left_depth + 2 == new_right_depth {
                // Right-left case
                let right_child = curr_mut.right_child_node.as_ref().unwrap().clone();
                let right_balance = compute_balance(&right_child.borrow());
                drop(curr_mut);

                if right_balance < 0 {
                    rotate_right(self, &right_child);
                }

                let new_root = rotate_left(self, &current_parent);
                bubble_up = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                continue;
            }

            drop(curr_mut);
            bubble_up = parent_weak.upgrade().and_then(|p| {
                p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
            });
        }

        new_node
    }

    /// Remove a given node from the tree.
    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        // Extract node data
        let (has_left, has_right, node_parent, node_left, node_right, node_left_count, node_right_count) = {
            let node_borrow = node.borrow();
            (
                node_borrow.left_child_node.is_some(),
                node_borrow.right_child_node.is_some(),
                node_borrow.parent_node.clone(),
                node_borrow.left_child_node.clone(),
                node_borrow.right_child_node.clone(),
                node_borrow.left_child_count,
                node_borrow.right_child_count,
            )
        };

        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;

        // If this node has children on both sides, bubble one of them upwards
        if has_left && has_right {
            let node_left_rc = node_left.as_ref().unwrap().clone();
            let node_right_rc = node_right.as_ref().unwrap().clone();

            let (candidate, lost_child) = if node_left_rc.borrow().depth >= node_right_rc.borrow().depth {
                // Left branch is deeper
                {
                    let mut left_mut = node_left_rc.borrow_mut();
                    left_mut.left_child_count -= 1;
                }
                let mut cand = node_left_rc.clone();
                while cand.borrow().right_child_node.is_some() {
                    let mut cand_mut = cand.borrow_mut();
                    cand_mut.right_child_count -= 1;
                    cand = cand_mut.right_child_node.clone().unwrap();
                }
                let lost = cand.borrow().left_child_node.clone();
                (cand, lost)
            } else {
                // Right branch is deeper
                {
                    let mut right_mut = node_right_rc.borrow_mut();
                    right_mut.right_child_count -= 1;
                }
                let mut cand = node_right_rc.clone();
                while cand.borrow().left_child_node.is_some() {
                    let mut cand_mut = cand.borrow_mut();
                    cand_mut.left_child_count -= 1;
                    cand = cand_mut.left_child_node.clone().unwrap();
                }
                let lost = cand.borrow().right_child_node.clone();
                (cand, lost)
            };

            let bubble_start = {
                let cand_borrow = candidate.borrow();
                cand_borrow.parent_node.as_ref().and_then(|w| w.upgrade()).unwrap()
            };

            // Detach candidate from its parent
            {
                let mut bubble_start_mut = bubble_start.borrow_mut();
                if bubble_start_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
                    bubble_start_mut.left_child_node = lost_child.clone();
                } else {
                    bubble_start_mut.right_child_node = lost_child.clone();
                }
            }

            if let Some(ref lost) = lost_child {
                lost.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Anchor candidate into the place where "node" used to be
            if let Some(ref node_parent_weak) = node_parent {
                if let Some(node_parent_strong) = node_parent_weak.upgrade() {
                    let mut parent_borrow = node_parent_strong.borrow_mut();
                    if parent_borrow.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
                        parent_borrow.left_child_node = Some(candidate.clone());
                    } else {
                        parent_borrow.right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                self.root_node = Some(candidate.clone());
            }

            candidate.borrow_mut().parent_node = node_parent.clone();

            // Copy children from node to candidate
            {
                let mut cand_mut = candidate.borrow_mut();
                cand_mut.left_child_node = node_left.clone();
                cand_mut.left_child_count = node_left_count;
                cand_mut.right_child_node = node_right.clone();
                cand_mut.right_child_count = node_right_count;
            }

            if let Some(ref left_child) = node_left {
                left_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if let Some(ref right_child) = node_right {
                right_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance up to candidate
            if !Rc::ptr_eq(&bubble_start, node) {
                let mut current_bubble: Option<Rc<RefCell<BOSNode>>> = Some(bubble_start.clone());
                while let Some(ref cb) = current_bubble {
                    if Rc::ptr_eq(cb, &candidate) {
                        break;
                    }

                    let cb_weak = Rc::downgrade(cb);
                    let cb_rc = cb.clone();

                    {
                        let mut cb_mut = cb_rc.borrow_mut();
                        let left_depth = child_depth(&cb_mut.left_child_node);
                        let right_depth = child_depth(&cb_mut.right_child_node);
                        cb_mut.depth = imax(left_depth, right_depth) as u32;

                        let balance = compute_balance(&cb_mut);
                        if balance > 1 {
                            // Rotate left. Check for right-left case first.
                            if let Some(ref right_child) = cb_mut.right_child_node {
                                if compute_balance(&right_child.borrow()) < 0 {
                                    let right_rc = right_child.clone();
                                    drop(cb_mut);
                                    rotate_right(self, &right_rc);
                                    cb_mut = cb_rc.borrow_mut();
                                }
                            }
                            let new_root = rotate_left(self, &cb_rc);
                            drop(cb_mut);
                            current_bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        } else if balance < -1 {
                            // Rotate right. Check for left-right case first.
                            if let Some(ref left_child) = cb_mut.left_child_node {
                                if compute_balance(&left_child.borrow()) > 0 {
                                    let left_rc = left_child.clone();
                                    drop(cb_mut);
                                    rotate_left(self, &left_rc);
                                    cb_mut = cb_rc.borrow_mut();
                                }
                            }
                            let new_root = rotate_right(self, &cb_rc);
                            drop(cb_mut);
                            current_bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }
                    }

                    current_bubble = cb_weak.upgrade().and_then(|p| {
                        p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                    });
                }
            }

            // Fix candidate's depth
            {
                let mut cand_mut = candidate.borrow_mut();
                let left_depth = child_depth(&cand_mut.left_child_node);
                let right_depth = child_depth(&cand_mut.right_child_node);
                cand_mut.depth = imax(left_depth, right_depth) as u32;
            }

            // Fix immediate parent node child count
            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref bu) = bubble_up {
                let mut bu_mut = bu.borrow_mut();
                if bu_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
                    bu_mut.left_child_count -= 1;
                } else {
                    bu_mut.right_child_count -= 1;
                }
            }
        } else {
            // Node has children on one side only (or none)
            if node_parent.is_none() {
                // Node was the root
                if has_left {
                    let left_rc = node_left.as_ref().unwrap().clone();
                    self.root_node = Some(left_rc.clone());
                    left_rc.borrow_mut().parent_node = None;
                } else {
                    let right_rc = node_right.as_ref().unwrap().clone();
                    self.root_node = Some(right_rc.clone());
                    right_rc.borrow_mut().parent_node = None;
                }
                bubble_up = None;
            } else {
                let candidate = if has_left { node_left.clone() } else { node_right.clone() };
                let candidate_count = if has_left { node_left_count } else { node_right_count };

                // Attach candidate to node's parent
                if let Some(ref node_parent_weak) = node_parent {
                    if let Some(node_parent_strong) = node_parent_weak.upgrade() {
                        let mut parent_borrow = node_parent_strong.borrow_mut();
                        if parent_borrow.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
                            parent_borrow.left_child_node = candidate.clone();
                            parent_borrow.left_child_count = candidate_count;
                        } else {
                            parent_borrow.right_child_node = candidate.clone();
                            parent_borrow.right_child_count = candidate_count;
                        }
                        if let Some(ref cand) = candidate {
                            cand.borrow_mut().parent_node = Some(Rc::downgrade(&node_parent_strong));
                        }
                    }
                }

                bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Rebalance up the tree
        let mut bubbling_finished = false;
        while let Some(ref bu) = bubble_up {
            if !bubbling_finished {
                let bu_weak = Rc::downgrade(bu);
                let bu_rc = bu.clone();

                {
                    let mut bu_mut = bu_rc.borrow_mut();
                    let left_depth = child_depth(&bu_mut.left_child_node);
                    let right_depth = child_depth(&bu_mut.right_child_node);
                    let new_depth = imax(left_depth, right_depth);
                    let depth_changed = bu_mut.depth != new_depth as u32;
                    bu_mut.depth = new_depth as u32;

                    // Rebalance
                    let balance = compute_balance(&bu_mut);
                    if balance < -1 {
                        if let Some(ref left_child) = bu_mut.left_child_node {
                            if compute_balance(&left_child.borrow()) > 0 {
                                let left_rc = left_child.clone();
                                drop(bu_mut);
                                rotate_left(self, &left_rc);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_right(self, &bu_rc);
                    } else if balance > 1 {
                        if let Some(ref right_child) = bu_mut.right_child_node {
                            if compute_balance(&right_child.borrow()) < 0 {
                                let right_rc = right_child.clone();
                                drop(bu_mut);
                                rotate_right(self, &right_rc);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_left(self, &bu_rc);
                    } else if !depth_changed {
                        bubbling_finished = true;
                    }
                }

                // Update child counts
                if let Some(ref bu_parent_weak) = bu_rc.borrow().parent_node {
                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
                        let mut parent_mut = bu_parent.borrow_mut();
                        if parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu_rc)) {
                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }

                bubble_up = bu_weak.upgrade().and_then(|p| {
                    p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                });
            } else {
                // Just update child counts
                if let Some(ref bu_parent_weak) = bu.borrow().parent_node {
                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
                        let mut parent_mut = bu_parent.borrow_mut();
                        if parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, bu)) {
                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }
                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Mark node as invalid and decrement weak ref
        {
            let mut node_mut = node.borrow_mut();
            node_mut.weak_ref_node_valid = 0;
        }

        // Call weak_unref
        self.bostree_node_weak_unref(node);
    }

    /// Decrease the weak reference count for a node; if that was the last reference,
    /// free the node and return None; otherwise return the node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;

        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_fn) = self.free_function {
                free_fn(node);
            }
            return None;
        } else if node_mut.weak_ref_node_valid == 1 {
            return Some(node.clone());
        }

        None
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(ref current) = node {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current.clone());
            } else if cmp < 0 {
                node = current.borrow().left_child_node.clone();
            } else {
                node = current.borrow().right_child_node.clone();
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        let mut index = index;

        while let Some(ref current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(current.clone());
                }
                index -= 1;
                node = current.borrow().right_child_node.clone();
            } else {
                node = current.borrow().left_child_node.clone();
            }
        }
        None
    }

    /// Print the tree (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }

        println!("digraph {{");
        println!("  ordering = out;");
        self.print_helper(&self.root_node.as_ref().unwrap().clone());
        println!("}}");
    }

    #[cfg(debug_assertions)]
    fn print_helper(&self, node: &Rc<RefCell<BOSNode>>) {
        let (key, left_count, right_count, depth, parent_key) = {
            let n = node.borrow();
            let parent_k = n.parent_node.as_ref().and_then(|w| w.upgrade()).map(|p| p.borrow().key.clone());
            (n.key.clone(), n.left_child_count, n.right_child_count, n.depth, parent_k)
        };

        println!("  {} [label=\"\\N ({},{},{})\"];", key, left_count, right_count, depth);

        if let Some(pk) = parent_key {
            println!("  {} -> {} [color=green];", key, pk);
        }

        if let Some(ref left) = node.borrow().left_child_node {
            let left_key = left.borrow().key.clone();
            println!("  {} -> {}", key, left_key);
            self.print_helper(left);
        }

        if let Some(ref right) = node.borrow().right_child_node {
            let right_key = right.borrow().key.clone();
            println!("  {} -> {}", key, right_key);
            self.print_helper(right);
        }
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // If has right child, go to right then all the way left
    if node.borrow().right_child_node.is_some() {
        let mut current = node.borrow().right_child_node.clone().unwrap();
        while current.borrow().left_child_node.is_some() {
            current = current.borrow().left_child_node.clone().unwrap();
        }
        return Some(current);
    }

    // Go up until we find a parent where we're in the left subtree
    let mut current = node.clone();
    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
                    current = parent;
                    continue;
                }
                return Some(parent);
            }
            None => return None,
        }
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // If has left child, go to left then all the way right
    if node.borrow().left_child_node.is_some() {
        let mut current = node.borrow().left_child_node.clone().unwrap();
        while current.borrow().right_child_node.is_some() {
            current = current.borrow().right_child_node.clone().unwrap();
        }
        return Some(current);
    }

    // Go up until we find a parent where we're in the right subtree
    let mut current = node.clone();
    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current)) {
                    current = parent;
                    continue;
                }
                return Some(parent);
            }
            None => return None,
        }
    }
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
                    counter += 1 + parent.borrow().left_child_count;
                }
                current = parent;
            }
            None => return counter,
        }
    }
}"}

