58	/// Helper function to get the depth of a node's child.
59	#[inline]
60	fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
61	    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
