64	/// Compute the balance factor of a node (right depth - left depth).
65	fn compute_balance(node: &BOSNode) -> i32 {
66	    let left_depth = child_depth(&node.left_child_node);
67	    let right_depth = child_depth(&node.right_child_node);
68	    right_depth - left_depth
69	}
