71	/// Rotate right and return the new root of this subtree.
72	fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
73	    // Rotate right:
74	    //
75	    //      P                     L
76	    //  L        R     -->    c1      P
77	    //c1 c2                        c2     R
78	    //
79	    let l = {
80	        let mut p_mut = p.borrow_mut();
81	        p_mut.left_child_node.take()
82	    };
83	
84	    let l = match l {
85	        Some(l) => l,
86	        None => return p.clone(),
87	    };
88	
89	    // Extract data from L
90	    let l_right = l.borrow().right_child_node.clone();
91	    let l_right_count = l.borrow().right_child_count;
92	    let p_parent = p.borrow().parent_node.clone();
93	    drop(l.borrow());
94	
95	    let l_rc = l.clone();
96	    let p_rc = p.clone();
97	
98	    // Update grandparent's child pointer
99	    if let Some(ref p_parent_weak) = p_parent {
100	        if let Some(p_parent_strong) = p_parent_weak.upgrade() {
101	            let mut parent_borrow = p_parent_strong.borrow_mut();
102	            if parent_borrow.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &p_rc)) {
103	                parent_borrow.left_child_node = Some(l_rc.clone());
104	            } else {
105	                parent_borrow.right_child_node = Some(l_rc.clone());
106	            }
107	        }
108	    } else {
109	        tree.root_node = Some(l_rc.clone());
110	    }
111	
112	    // Update L's parent
113	    {
114	        let mut l_mut = l_rc.borrow_mut();
115	        l_mut.parent_node = p_parent;
116	    }
117	
118	    // Update P's left child and counts
119	    {
120	        let mut p_mut = p_rc.borrow_mut();
121	        p_mut.left_child_node = l_right;
122	        p_mut.left_child_count = l_right_count;
123	
124	        if let Some(ref left_child) = p_mut.left_child_node {
125	            left_child.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc));
126	        }
127	
128	        let left_depth = child_depth(&p_mut.left_child_node);
129	        let right_depth = child_depth(&p_mut.right_child_node);
130	        p_mut.depth = imax(left_depth, right_depth) as u32;
131	        p_mut.parent_node = Some(Rc::downgrade(&l_rc));
132	    }
133	
134	    // Update L's right child and counts
135	    {
136	        let mut l_mut = l_rc.borrow_mut();
137	        l_mut.right_child_node = Some(p_rc.clone());
138	        p_rc.borrow_mut().parent_node = Some(Rc::downgrade(&l_rc));
139	
140	        l_mut.right_child_count = p_rc.borrow().left_child_count + p_rc.borrow().right_child_count + 1;
141	
142	        let left_depth = child_depth(&l_mut.left_child_node);
143	        let right_depth = child_depth(&l_mut.right_child_node);
144	        l_mut.depth = imax(left_depth, right_depth) as u32;
145	    }
146	
147	    l_rc
148	}
