349	        while let Some(ref current_parent) = bubble_up {
350	            let parent_weak = Rc::downgrade(current_parent);
351	
352	            // Update depth
353	            let mut curr_mut = current_parent.borrow_mut();
354	            let new_left_depth = child_depth(&curr_mut.left_child_node);
355	            let new_right_depth = child_depth(&curr_mut.right_child_node);
356	            let max_depth = imax(new_left_depth, new_right_depth);
357	
358	            let depth_changed = curr_mut.depth != max_depth as u32;
359	            if depth_changed {
360	                curr_mut.depth = max_depth as u32;
361	            } else {
362	                break;
363	            }
364	
365	            // Check AVL property
366	            if new_left_depth - 2 == new_right_depth {
367	                // Left-right case
368	                let left_child = curr_mut.left_child_node.as_ref().unwrap().clone();
369	                let left_balance = compute_balance(&left_child.borrow());
370	                drop(curr_mut);
371	
372	                if left_balance > 0 {
373	                    rotate_left(self, &left_child);
374	                }
375	
376	                let new_root = rotate_right(self, &current_parent);
377	                bubble_up = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
378	                continue;
379	            } else if new_left_depth + 2 == new_right_depth {
380	                // Right-left case
381	                let right_child = curr_mut.right_child_node.as_ref().unwrap().clone();
382	                let right_balance = compute_balance(&right_child.borrow());
383	                drop(curr_mut);
384	
385	                if right_balance < 0 {
386	                    rotate_right(self, &right_child);
387	                }
388	
389	                let new_root = rotate_left(self, &current_parent);
390	                bubble_up = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
391	                continue;
392	            }
393	
394	            drop(curr_mut);
395	            bubble_up = parent_weak.upgrade().and_then(|p| {
396	                p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
397	            });
398	        }
399	
400	        new_node
401	    }
402	
403	    /// Remove a given node from the tree.
404	    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
405	        // Extract node data
406	        let (has_left, has_right, node_parent, node_left, node_right, node_left_count, node_right_count) = {
407	            let node_borrow = node.borrow();
408	            (
409	                node_borrow.left_child_node.is_some(),
410	                node_borrow.right_child_node.is_some(),
411	                node_borrow.parent_node.clone(),
412	                node_borrow.left_child_node.clone(),
413	                node_borrow.right_child_node.clone(),
414	                node_borrow.left_child_count,
415	                node_borrow.right_child_count,
416	            )
417	        };
418	
419	        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;
420	
421	        // If this node has children on both sides, bubble one of them upwards
422	        if has_left && has_right {
423	            let node_left_rc = node_left.as_ref().unwrap().clone();
424	            let node_right_rc = node_right.as_ref().unwrap().clone();
425	
426	            let (candidate, lost_child) = if node_left_rc.borrow().depth >= node_right_rc.borrow().depth {
427	                // Left branch is deeper
428	                {
429	                    let mut left_mut = node_left_rc.borrow_mut();
430	                    left_mut.left_child_count -= 1;
431	                }
432	                let mut cand = node_left_rc.clone();
433	                while cand.borrow().right_child_node.is_some() {
434	                    let mut cand_mut = cand.borrow_mut();
435	                    cand_mut.right_child_count -= 1;
436	                    cand = cand_mut.right_child_node.clone().unwrap();
437	                }
438	                let lost = cand.borrow().left_child_node.clone();
439	                (cand, lost)
440	            } else {
441	                // Right branch is deeper
442	                {
443	                    let mut right_mut = node_right_rc.borrow_mut();
444	                    right_mut.right_child_count -= 1;
445	                }
446	                let mut cand = node_right_rc.clone();
447	                while cand.borrow().left_child_node.is_some() {
448	                    let mut cand_mut = cand.borrow_mut();
449	                    cand_mut.left_child_count -= 1;
450	                    cand = cand_mut.left_child_node.clone().unwrap();
451	                }
452	                let lost = cand.borrow().right_child_node.clone();
453	                (cand, lost)
454	            };
455	
456	            let bubble_start = {
457	                let cand_borrow = candidate.borrow();
458	                cand_borrow.parent_node.as_ref().and_then(|w| w.upgrade()).unwrap()
459	            };
460	
461	            // Detach candidate from its parent
462	            {
463	                let mut bubble_start_mut = bubble_start.borrow_mut();
464	                if bubble_start_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
465	                    bubble_start_mut.left_child_node = lost_child.clone();
466	                } else {
467	                    bubble_start_mut.right_child_node = lost_child.clone();
468	                }
469	            }
470	
471	            if let Some(ref lost) = lost_child {
472	                lost.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
473	            }
474	
475	            // Anchor candidate into the place where "node" used to be
476	            if let Some(ref node_parent_weak) = node_parent {
477	                if let Some(node_parent_strong) = node_parent_weak.upgrade() {
478	                    let mut parent_borrow = node_parent_strong.borrow_mut();
479	                    if parent_borrow.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
480	                        parent_borrow.left_child_node = Some(candidate.clone());
481	                    } else {
482	                        parent_borrow.right_child_node = Some(candidate.clone());
483	                    }
484	                }
485	            } else {
486	                self.root_node = Some(candidate.clone());
487	            }
488	
489	            candidate.borrow_mut().parent_node = node_parent.clone();
490	
491	            // Copy children from node to candidate
492	            {
493	                let mut cand_mut = candidate.borrow_mut();
494	                cand_mut.left_child_node = node_left.clone();
495	                cand_mut.left_child_count = node_left_count;
496	                cand_mut.right_child_node = node_right.clone();
497	                cand_mut.right_child_count = node_right_count;
498	            }
499	
500	            if let Some(ref left_child) = node_left {
501	                left_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
502	            }
503	
504	            if let Some(ref right_child) = node_right {
505	                right_child.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
506	            }
507	
508	            // Rebalance up to candidate
509	            if !Rc::ptr_eq(&bubble_start, node) {
510	                let mut current_bubble: Option<Rc<RefCell<BOSNode>>> = Some(bubble_start.clone());
511	                while let Some(ref cb) = current_bubble {
512	                    if Rc::ptr_eq(cb, &candidate) {
513	                        break;
514	                    }
515	
516	                    let cb_weak = Rc::downgrade(cb);
517	                    let cb_rc = cb.clone();
518	
519	                    {
520	                        let mut cb_mut = cb_rc.borrow_mut();
521	                        let left_depth = child_depth(&cb_mut.left_child_node);
522	                        let right_depth = child_depth(&cb_mut.right_child_node);
523	                        cb_mut.depth = imax(left_depth, right_depth) as u32;
524	
525	                        let balance = compute_balance(&cb_mut);
526	                        if balance > 1 {
527	                            // Rotate left. Check for right-left case first.
528	                            if let Some(ref right_child) = cb_mut.right_child_node {
529	                                if compute_balance(&right_child.borrow()) < 0 {
530	                                    let right_rc = right_child.clone();
531	                                    drop(cb_mut);
532	                                    rotate_right(self, &right_rc);
533	                                    cb_mut = cb_rc.borrow_mut();
534	                                }
535	                            }
536	                            let new_root = rotate_left(self, &cb_rc);
537	                            drop(cb_mut);
538	                            current_bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
539	                            continue;
540	                        } else if balance < -1 {
541	                            // Rotate right. Check for left-right case first.
542	                            if let Some(ref left_child) = cb_mut.left_child_node {
543	                                if compute_balance(&left_child.borrow()) > 0 {
544	                                    let left_rc = left_child.clone();
545	                                    drop(cb_mut);
546	                                    rotate_left(self, &left_rc);
547	                                    cb_mut = cb_rc.borrow_mut();
548	                                }
549	                            }
550	                            let new_root = rotate_right(self, &cb_rc);
551	                            drop(cb_mut);
552	                            current_bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
553	                            continue;
554	                        }
555	                    }
556	
557	                    current_bubble = cb_weak.upgrade().and_then(|p| {
558	                        p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
559	                    });
560	                }
561	            }
562	
563	            // Fix candidate's depth
564	            {
565	                let mut cand_mut = candidate.borrow_mut();
566	                let left_depth = child_depth(&cand_mut.left_child_node);
567	                let right_depth = child_depth(&cand_mut.right_child_node);
568	                cand_mut.depth = imax(left_depth, right_depth) as u32;
569	            }
570	
571	            // Fix immediate parent node child count
572	            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
573	            if let Some(ref bu) = bubble_up {
574	                let mut bu_mut = bu.borrow_mut();
575	                if bu_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
576	                    bu_mut.left_child_count -= 1;
577	                } else {
578	                    bu_mut.right_child_count -= 1;
579	                }
580	            }
581	        } else {
582	            // Node has children on one side only (or none)
583	            if node_parent.is_none() {
584	                // Node was the root
585	                if has_left {
586	                    let left_rc = node_left.as_ref().unwrap().clone();
587	                    self.root_node = Some(left_rc.clone());
588	                    left_rc.borrow_mut().parent_node = None;
589	                } else {
590	                    let right_rc = node_right.as_ref().unwrap().clone();
591	                    self.root_node = Some(right_rc.clone());
592	                    right_rc.borrow_mut().parent_node = None;
593	                }
594	                bubble_up = None;
595	            } else {
596	                let candidate = if has_left { node_left.clone() } else { node_right.clone() };
597	                let candidate_count = if has_left { node_left_count } else { node_right_count };
598	
599	                // Attach candidate to node's parent
600	                if let Some(ref node_parent_weak) = node_parent {
601	                    if let Some(node_parent_strong) = node_parent_weak.upgrade() {
602	                        let mut parent_borrow = node_parent_strong.borrow_mut();
603	                        if parent_borrow.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
604	                            parent_borrow.left_child_node = candidate.clone();
605	                            parent_borrow.left_child_count = candidate_count;
606	                        } else {
607	                            parent_borrow.right_child_node = candidate.clone();
608	                            parent_borrow.right_child_count = candidate_count;
609	                        }
610	                        if let Some(ref cand) = candidate {
611	                            cand.borrow_mut().parent_node = Some(Rc::downgrade(&node_parent_strong));
612	                        }
613	                    }
614	                }
615	
616	                bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
617	            }
618	        }
619	
620	        // Rebalance up the tree
621	        let mut bubbling_finished = false;
622	        while let Some(ref bu) = bubble_up {
623	            if !bubbling_finished {
624	                let bu_weak = Rc::downgrade(bu);
625	                let bu_rc = bu.clone();
626	
627	                {
628	                    let mut bu_mut = bu_rc.borrow_mut();
629	                    let left_depth = child_depth(&bu_mut.left_child_node);
630	                    let right_depth = child_depth(&bu_mut.right_child_node);
631	                    let new_depth = imax(left_depth, right_depth);
632	                    let depth_changed = bu_mut.depth != new_depth as u32;
633	                    bu_mut.depth = new_depth as u32;
634	
635	                    // Rebalance
636	                    let balance = compute_balance(&bu_mut);
637	                    if balance < -1 {
638	                        if let Some(ref left_child) = bu_mut.left_child_node {
639	                            if compute_balance(&left_child.borrow()) > 0 {
640	                                let left_rc = left_child.clone();
641	                                drop(bu_mut);
642	                                rotate_left(self, &left_rc);
643	                                bu_mut = bu_rc.borrow_mut();
644	                            }
645	                        }
646	                        drop(bu_mut);
647	                        rotate_right(self, &bu_rc);
648	                    } else if balance > 1 {
649	                        if let Some(ref right_child) = bu_mut.right_child_node {
650	                            if compute_balance(&right_child.borrow()) < 0 {
651	                                let right_rc = right_child.clone();
652	                                drop(bu_mut);
653	                                rotate_right(self, &right_rc);
654	                                bu_mut = bu_rc.borrow_mut();
655	                            }
656	                        }
657	                        drop(bu_mut);
658	                        rotate_left(self, &bu_rc);
659	                    } else if !depth_changed {
660	                        bubbling_finished = true;
661	                    }
662	                }
663	
664	                // Update child counts
665	                if let Some(ref bu_parent_weak) = bu_rc.borrow().parent_node {
666	                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
667	                        let mut parent_mut = bu_parent.borrow_mut();
668	                        if parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu_rc)) {
669	                            parent_mut.left_child_count -= 1;
670	                        } else {
671	                            parent_mut.right_child_count -= 1;
672	                        }
673	                    }
674	                }
675	
676	                bubble_up = bu_weak.upgrade().and_then(|p| {
677	                    p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
678	                });
679	            } else {
680	                // Just update child counts
681	                if let Some(ref bu_parent_weak) = bu.borrow().parent_node {
682	                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
683	                        let mut parent_mut = bu_parent.borrow_mut();
684	                        if parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, bu)) {
685	                            parent_mut.left_child_count -= 1;
686	                        } else {
687	                            parent_mut.right_child_count -= 1;
688	                        }
689	                    }
690	                }
691	                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
692	            }
693	        }
694	
695	        // Mark node as invalid and decrement weak ref
696	        {
697	            let mut node_mut = node.borrow_mut();
698	            node_mut.weak_ref_node_valid = 0;
699	        }
700	
701	        // Call weak_unref
702	        self.bostree_node_weak_unref(node);
703	    }
704	
705	    /// Decrease the weak reference count for a node; if that was the last reference,
706	    /// free the node and return None; otherwise return the node.
707	    pub fn bostree_node_weak_unref(
708	        &mut self,
709	        node: &Rc<RefCell<BOSNode>>,
710	    ) -> Option<Rc<RefCell<BOSNode>>> {
711	        let mut node_mut = node.borrow_mut();
712	        node_mut.weak_ref_count -= 1;
713	
714	        if node_mut.weak_ref_count == 0 {
715	            if let Some(ref free_fn) = self.free_function {
716	                free_fn(node);
717	            }
718	            return None;
719	        } else if node_mut.weak_ref_node_valid == 1 {
720	            return Some(node.clone());
721	        }
722	
723	        None
724	    }
