726	    /// Lookup a node in the tree by its key.
727	    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
728	        let mut node = self.root_node.clone();
729	        while let Some(ref current) = node {
730	            let cmp = (self.cmp_function)(key, &current.borrow().key);
731	            if cmp == 0 {
732	                return Some(current.clone());
733	            } else if cmp < 0 {
734	                node = current.borrow().left_child_node.clone();
735	            } else {
736	                node = current.borrow().right_child_node.clone();
737	            }
738	        }
739	        None
740	    }
741	
742	    /// Return the node at the given in-order index (starting at 0).
743	    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
744	        let mut node = self.root_node.clone();
745	        let mut index = index;
746	
747	        while let Some(ref current) = node {
748	            let left_count = current.borrow().left_child_count;
749	            if left_count <= index {
750	                index -= left_count;
751	                if index == 0 {
752	                    return Some(current.clone());
753	                }
754	                index -= 1;
755	                node = current.borrow().right_child_node.clone();
756	            } else {
757	                node = current.borrow().left_child_node.clone();
758	            }
759	        }
760	        None
761	    }
