763	    /// Print the tree (only available in debug builds).
764	    #[cfg(debug_assertions)]
765	    pub fn bostree_print(&self) {
766	        if self.root_node.is_none() {
767	            return;
768	        }
769	
770	        println!("digraph {{");
771	        println!("  ordering = out;");
772	        self.print_helper(&self.root_node.as_ref().unwrap().clone());
773	        println!("}}");
774	    }
