776	    #[cfg(debug_assertions)]
777	    fn print_helper(&self, node: &Rc<RefCell<BOSNode>>) {
778	        let (key, left_count, right_count, depth, parent_key) = {
779	            let n = node.borrow();
780	            let parent_k = n.parent_node.as_ref().and_then(|w| w.upgrade()).map(|p| p.borrow().key.clone());
781	            (n.key.clone(), n.left_child_count, n.right_child_count, n.depth, parent_k)
782	        };
783	
784	        println!("  {} [label=\"\\N ({},{},{})\"];", key, left_count, right_count, depth);
785	
786	        if let Some(pk) = parent_key {
787	            println!("  {} -> {} [color=green];", key, pk);
788	        }
789	
790	        if let Some(ref left) = node.borrow().left_child_node {
791	            let left_key = left.borrow().key.clone();
792	            println!("  {} -> {}", key, left_key);
793	            self.print_helper(left);
794	        }
795	
796	        if let Some(ref right) = node.borrow().right_child_node {
797	            let right_key = right.borrow().key.clone();
798	            println!("  {} -> {}", key, right_key);
799	            self.print_helper(right);
800	        }
801	    }
802	}
