804	/// Increase the weak reference count for a node and return the node.
805	pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
806	    node.borrow_mut().weak_ref_count += 1;
807	    node.clone()
808	}
