810	/// Return the next node in an in-order traversal.
811	pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
812	    // If has right child, go to right then all the way left
813	    if node.borrow().right_child_node.is_some() {
814	        let mut current = node.borrow().right_child_node.clone().unwrap();
815	        while current.borrow().left_child_node.is_some() {
816	            current = current.borrow().left_child_node.clone().unwrap();
817	        }
818	        return Some(current);
819	    }
820	
821	    // Go up until we find a parent where we're in the left subtree
822	    let mut current = node.clone();
823	    loop {
824	        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
825	        match parent_opt {
826	            Some(parent) => {
827	                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
828	                    current = parent;
829	                    continue;
830	                }
831	                return Some(parent);
832	            }
833	            None => return None,
834	        }
835	    }
836	}
837	
838	/// Return the previous node in an in-order traversal.
839	pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
840	    // If has left child, go to left then all the way right
841	    if node.borrow().left_child_node.is_some() {
842	        let mut current = node.borrow().left_child_node.clone().unwrap();
843	        while current.borrow().right_child_node.is_some() {
844	            current = current.borrow().right_child_node.clone().unwrap();
845	        }
846	        return Some(current);
847	    }
848	
849	    // Go up until we find a parent where we're in the right subtree
850	    let mut current = node.clone();
851	    loop {
852	        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
853	        match parent_opt {
854	            Some(parent) => {
855	                if parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current)) {
856	                    current = parent;
857	                    continue;
858	                }
859	                return Some(parent);
860	            }
861	            None => return None,
862	        }
863	    }
864	}
865	
866	/// Return the rank (in-order index) of the given node.
867	pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
868	    let mut counter = node.borrow().left_child_count;
869	    let mut current = node.clone();
870	
871	    loop {
872	        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
873	        match parent_opt {
874	            Some(parent) => {
875	                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
876	                    counter += 1 + parent.borrow().left_child_count;
877	                }
878	                current = parent;
879	            }
880	            None => return counter,
881	        }
