/// Type alias for a key comparison function.
/// Should return a positive value if `b` is larger than `a`,
/// a negative value if `a` is larger, and zero if equal.
pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;

/// Type alias for a free function which will be called on nodes
/// that are removed.
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

/// Helper function to compute max of two integers.
#[inline]
fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

/// Helper function to get the depth of a node's child.
#[inline]
fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
}

/// Compute the balance factor of a node (right depth - left depth).
fn compute_balance(node: &BOSNode) -> i32 {
    child_depth(&node.right_child_node) - child_depth(&node.left_child_node)
