/// Rotate right and return the new root of this subtree.
fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = {
        let mut p_mut = p.borrow_mut();
        p_mut.left_child_node.take()
    };

    let l = match l {
        Some(l) => l,
        None => return p.clone(),
    };

    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    let p_parent = p.borrow().parent_node.clone();
    drop(l.borrow());

    let l_rc = l.clone();
    let p_rc = p.clone();

    // Update grandparent's child pointer
    if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_strong) = p_parent_weak.upgrade() {
            let mut parent_borrow = p_parent_strong.borrow_mut();
            let is_left = parent_borrow.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &p_rc));
