                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }

                bubble_up = bu_weak.upgrade().and_then(|p| {
                    p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                });
            } else {
                if let Some(ref bu_parent_weak) = bu.borrow().parent_node {
                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
                        let mut parent_mut = bu_parent.borrow_mut();
                        let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, bu));
                        if is_left {
                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }
                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Mark node as invalid and decrement weak ref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    /// Decrease the weak reference count for a node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;

        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_fn) = self.free_function {
                free_fn(node);
            }
            return None;
        } else if node_mut.weak_ref_node_valid == 1 {
            return Some(node.clone());
        }

        None
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(ref current) = node {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current.clone());
            } else if cmp < 0 {
                node = current.borrow().left_child_node.clone();
            } else {
                node = current.borrow().right_child_node.clone();
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        let mut index = index;

        while let Some(ref current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(current.clone());
                }
                index -= 1;
                node = current.borrow().right_child_node.clone();
            } else {
                node = current.borrow().left_child_node.clone();
            }
        }
        None
    }

    /// Print the tree (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }

        println!("digraph {{");
        println!("  ordering = out;");
        self.print_helper(&self.root_node.as_ref().unwrap().clone());
        println!("}}");
    }

    #[cfg(debug_assertions)]
    fn print_helper(&self, node: &Rc<RefCell<BOSNode>>) {
        let (key, left_count, right_count, depth, parent_key) = {
            let n = node.borrow();
            let parent_k = n.parent_node.as_ref().and_then(|w| w.upgrade()).map(|p| p.borrow().key.clone());
            (n.key.clone(), n.left_child_count, n.right_child_count, n.depth, parent_k)
        };

        println!("  {} [label=\"\\N ({},{},{})\"];", key, left_count, right_count, depth);

        if let Some(pk) = parent_key {
            println!("  {} -> {} [color=green];", key, pk);
        }

        if let Some(ref left) = node.borrow().left_child_node {
            let left_key = left.borrow().key.clone();
            drop(node.borrow());
            println!("  {} -> {}", key, left_key);
            self.print_helper(left);
        }

        if let Some(ref right) = node.borrow().right_child_node {
            let right_key = right.borrow().key.clone();
            drop(node.borrow());
            println!("  {} -> {}", key, right_key);
            self.print_helper(right);
        }
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().right_child_node.is_some() {
        let mut current = node.borrow().right_child_node.clone().unwrap();
        while current.borrow().left_child_node.is_some() {
            current = current.borrow().left_child_node.clone().unwrap();
        }
        return Some(current);
    }

    let mut current = node.clone();
    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
                    current = parent;
                    continue;
                }
                return Some(parent);
            }
            None => return None,
        }
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().left_child_node.is_some() {
        let mut current = node.borrow().left_child_node.clone().unwrap();
        while current.borrow().right_child_node.is_some() {
            current = current.borrow().right_child_node.clone().unwrap();
        }
        return Some(current);
    }

    let mut current = node.clone();
    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current)) {
                    current = parent;
                    continue;
                }
                return Some(parent);
            }
            None => return None,
        }
    }
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let parent_opt = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent_opt {
            Some(parent) => {
                if parent.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
                    counter += 1 + parent.borrow().left_child_count;
                }
                current = parent;
            }
            None => return counter,
        }
    }
}"}

