                let right_depth = child_depth(&cand_mut.right_child_node);
                cand_mut.depth = imax(left_depth, right_depth) as u32;
            }

            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref bu) = bubble_up {
                let mut bu_mut = bu.borrow_mut();
                let is_left = bu_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                if is_left {
                    bu_mut.left_child_count -= 1;
                } else {
                    bu_mut.right_child_count -= 1;
                }
            }
        } else {
            if node_parent.is_none() {
                if has_left {
                    let left_rc = node_left.as_ref().unwrap().clone();
                    self.root_node = Some(left_rc.clone());
                    left_rc.borrow_mut().parent_node = None;
                } else {
                    let right_rc = node_right.as_ref().unwrap().clone();
                    self.root_node = Some(right_rc.clone());
                    right_rc.borrow_mut().parent_node = None;
                }
                bubble_up = None;
            } else {
                let candidate = if has_left { node_left.clone() } else { node_right.clone() };
                let candidate_count = if has_left { node_left_count } else { node_right_count };

                if let Some(ref np_weak) = node_parent {
                    if let Some(np) = np_weak.upgrade() {
                        let mut np_mut = np.borrow_mut();
                        let is_left = np_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                        if is_left {
                            np_mut.left_child_node = candidate.clone();
                            np_mut.left_child_count = candidate_count;
                        } else {
                            np_mut.right_child_node = candidate.clone();
                            np_mut.right_child_count = candidate_count;
                        }
                        if let Some(ref cand) = candidate {
                            cand.borrow_mut().parent_node = Some(Rc::downgrade(&np));
                        }
                    }
                }

                bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
            }
        }

        let mut bubbling_finished = false;
        while let Some(bu) = bubble_up {
            if !bubbling_finished {
                let bu_weak = Rc::downgrade(&bu);
                let bu_rc = bu.clone();

                {
                    let mut bu_mut = bu_rc.borrow_mut();
                    let left_depth = child_depth(&bu_mut.left_child_node);
                    let right_depth = child_depth(&bu_mut.right_child_node);
                    let new_depth = imax(left_depth, right_depth) as u32;
                    let depth_changed = bu_mut.depth != new_depth;
                    bu_mut.depth = new_depth;

                    let balance = compute_balance(&bu_mut);
                    if balance < -1 {
                        if let Some(ref lc) = bu_mut.left_child_node {
                            if compute_balance(&lc.borrow()) > 0 {
                                let lc_copy = lc.clone();
                                drop(bu_mut);
                                rotate_left(self, &lc_copy);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_right(self, &bu_rc);
                    } else if balance > 1 {
                        if let Some(ref rc) = bu_mut.right_child_node {
                            if compute_balance(&rc.borrow()) < 0 {
                                let rc_copy = rc.clone();
                                drop(bu_mut);
                                rotate_right(self, &rc_copy);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_left(self, &bu_rc);
                    } else if !depth_changed {
                        bubbling_finished = true;
                    }
                }

