#[inline]
fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

#[inline]
fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
}

fn compute_balance(node: &BOSNode) -> i32 {
    child_depth(&node.right_child_node) - child_depth(&node.left_child_node)
}

fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = {
        let mut p_mut = p.borrow_mut();
        p_mut.left_child_node.take()
    };

    let l = match l {
        Some(l) => l,
        None => return p.clone(),
    };

    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    let p_parent = p.borrow().parent_node.clone();
    drop(l.borrow());

    let l_rc = l.clone();
    let p_rc = p.clone();

    // Update grandparent's child pointer
    if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_strong) = p_parent_weak.upgrade() {
            let mut parent_borrow = p_parent_strong.borrow_mut();
            let is_left = parent_borrow.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &p_rc));
            if is_left {
                parent_borrow.left_child_node = Some(l_rc.clone());
            } else {
                parent_borrow.right_child_node = Some(l_rc.clone());
            }
        }
    } else {
        tree.root_node = Some(l_rc.clone());
    }

    // Update L's parent
    l_rc.borrow_mut().parent_node = p_parent.clone();

    // Update P's left child and counts
    {
        let mut p_mut = p_rc.borrow_mut();
        p_mut.left_child_node = l_right;
        p_mut.left_child_count = l_right_count;

        if let Some(ref lc) = p_mut.left_child_node {
            lc.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc));
        }

        let left_depth = child_depth(&p_mut.left_child_node);
        let right_depth = child_depth(&p_mut.right_child_node);
        p_mut.depth = imax(left_depth, right_depth) as u32;
        p_mut.parent_node = Some(Rc::downgrade(&l_rc));
    }

    // Update L's right child and counts
    {
        let mut l_mut = l_rc.borrow_mut();
        l_mut.right_child_node = Some(p_rc.clone());

        let p_left_count = p_rc.borrow().left_child_count;
        let p_right_count = p_rc.borrow().right_child_count;
        l_mut.right_child_count = p_left_count + p_right_count + 1;

        p_rc.borrow_mut().parent_node = Some(Rc::downgrade(&l_rc));

        let left_depth = child_depth(&l_mut.left_child_node);
        let right_depth = child_depth(&l_mut.right_child_node);
        l_mut.depth = imax(left_depth, right_depth) as u32;
    }

    l_rc
}

fn rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = {
        let mut p_mut = p.borrow_mut();
        p_mut.right_child_node.take()
    };

    let r = match r {
        Some(r) => r,
        None => return p.clone(),
    };

    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    let p_parent = p.borrow().parent_node.clone();
    drop(r.borrow());

    let r_rc = r.clone();
    let p_rc = p.clone();

    // Update grandparent's child pointer
    if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_strong) = p_parent_weak.upgrade() {
            let mut parent_borrow = p_parent_strong.borrow_mut();
            let is_left = parent_borrow.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &p_rc));
            if is_left {
                parent_borrow.left_child_node = Some(r_rc.clone());
            } else {
                parent_borrow.right_child_node = Some(r_rc.clone());
            }
        }
    } else {
        tree.root_node = Some(r_rc.clone());
    }

    // Update R's parent
    r_rc.borrow_mut().parent_node = p_parent.clone();

    // Update P's right child and counts
    {
        let mut p_mut = p_rc.borrow_mut();
        p_mut.right_child_node = r_left;
        p_mut.right_child_count = r_left_count;

        if let Some(ref rc) = p_mut.right_child_node {
            rc.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc));
        }

        let left_depth = child_depth(&p_mut.left_child_node);
        let right_depth = child_depth(&p_mut.right_child_node);
        p_mut.depth = imax(left_depth, right_depth) as u32;
        p_mut.parent_node = Some(Rc::downgrade(&r_rc));
    }

    // Update R's left child and counts
    {
        let mut r_mut = r_rc.borrow_mut();
        r_mut.left_child_node = Some(p_rc.clone());

        let p_left_count = p_rc.borrow().left_child_count;
        let p_right_count = p_rc.borrow().right_child_count;
        r_mut.left_child_count = p_left_count + p_right_count + 1;

        p_rc.borrow_mut().parent_node = Some(Rc::downgrade(&r_rc));

        let left_depth = child_depth(&r_mut.left_child_node);
        let right_depth = child_depth(&r_mut.right_child_node);
        r_mut.depth = imax(left_depth, right_depth) as u32;
    }

    r_rc
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            let root_borrow = root.borrow();
            root_borrow.left_child_count + root_borrow.right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        if self.root_node.is_none() {
            let new_node = Rc::new(RefCell::new(BOSNode {
                left_child_count: 0,
                right_child_count: 0,
                depth: 1,
                left_child_node: None,
                right_child_node: None,
                parent_node: None,
                key,
                data,
                weak_ref_count: 1,
                weak_ref_node_valid: 1,
            }));
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        let mut current = self.root_node.clone().unwrap();
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;

        loop {
            let cmp = (self.cmp_function)(&key, &current.borrow().key);

            if cmp < 0 {
                let left_count = current.borrow().left_child_count;
                let left_opt = current.borrow().left_child_node.clone();
                if let Some(next) = left_opt {
                    current.borrow_mut().left_child_count = left_count + 1;
                    parent = Some(current);
                    current = next;
                } else {
                    current.borrow_mut().left_child_count = left_count + 1;
                    let new_node = Rc::new(RefCell::new(BOSNode {
                        left_child_count: 0,
                        right_child_count: 0,
                        depth: 1,
                        left_child_node: None,
                        right_child_node: None,
                        parent_node: Some(Rc::downgrade(&current)),
                        key,
                        data,
                        weak_ref_count: 1,
                        weak_ref_node_valid: 1,
                    }));
                    current.borrow_mut().left_child_node = Some(new_node.clone());
                    drop(current.borrow_mut());

                    // Rebalance from parent up
                    let mut bubble = parent.clone();
                    while let Some(ref p) = bubble {
                        let p_weak = Rc::downgrade(p);
                        let left_depth = child_depth(&p.borrow().left_child_node);
                        let right_depth = child_depth(&p.borrow().right_child_node);
                        let new_depth = imax(left_depth, right_depth) as u32;
                        let depth_changed = p.borrow().depth != new_depth;

                        if depth_changed {
                            p.borrow_mut().depth = new_depth;
                        } else {
                            break;
                        }

                        // Check for AVL violation
                        if left_depth - right_depth >= 2 {
                            let left = p.borrow().left_child_node.as_ref().unwrap().clone();
                            let balance = compute_balance(&left.borrow());
                            drop(p.borrow_mut());

                            if balance > 0 {
                                rotate_left(self, &left);
                            }
                            let new_root = rotate_right(self, p);
                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }

                        if right_depth - left_depth >= 2 {
                            let right = p.borrow().right_child_node.as_ref().unwrap().clone();
                            let balance = compute_balance(&right.borrow());
                            drop(p.borrow_mut());

                            if balance < 0 {
                                rotate_right(self, &right);
                            }
                            let new_root = rotate_left(self, p);
                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }

                        drop(p.borrow_mut());
                        bubble = p_weak.upgrade().and_then(|pp| {
                            pp.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                        });
                    }
                    return new_node;
                }
            } else {
                let right_count = current.borrow().right_child_count;
                let right_opt = current.borrow().right_child_node.clone();
                if let Some(next) = right_opt {
                    current.borrow_mut().right_child_count = right_count + 1;
                    parent = Some(current);
                    current = next;
                } else {
                    current.borrow_mut().right_child_count = right_count + 1;
                    let new_node = Rc::new(RefCell::new(BOSNode {
                        left_child_count: 0,
                        right_child_count: 0,
                        depth: 1,
                        left_child_node: None,
                        right_child_node: None,
                        parent_node: Some(Rc::downgrade(&current)),
                        key,
                        data,
                        weak_ref_count: 1,
                        weak_ref_node_valid: 1,
                    }));
                    current.borrow_mut().right_child_node = Some(new_node.clone());
                    drop(current.borrow_mut());

                    // Rebalance from parent up
                    let mut bubble = parent.clone();
                    while let Some(ref p) = bubble {
                        let p_weak = Rc::downgrade(p);
                        let left_depth = child_depth(&p.borrow().left_child_node);
                        let right_depth = child_depth(&p.borrow().right_child_node);
                        let new_depth = imax(left_depth, right_depth) as u32;
                        let depth_changed = p.borrow().depth != new_depth;

                        if depth_changed {
                            p.borrow_mut().depth = new_depth;
                        } else {
                            break;
                        }

                        // Check for AVL violation
                        if left_depth - right_depth >= 2 {
                            let left = p.borrow().left_child_node.as_ref().unwrap().clone();
                            let balance = compute_balance(&left.borrow());
                            drop(p.borrow_mut());

                            if balance > 0 {
                                rotate_left(self, &left);
                            }
                            let new_root = rotate_right(self, p);
                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }

                        if right_depth - left_depth >= 2 {
                            let right = p.borrow().right_child_node.as_ref().unwrap().clone();
                            let balance = compute_balance(&right.borrow());
                            drop(p.borrow_mut());

                            if balance < 0 {
                                rotate_right(self, &right);
                            }
                            let new_root = rotate_left(self, p);
                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }

                        drop(p.borrow_mut());
                        bubble = p_weak.upgrade().and_then(|pp| {
                            pp.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                        });
                    }
                    return new_node;
                }
            }
        }
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let (has_left, has_right, node_parent, node_left, node_right, node_left_count, node_right_count) = {
            let n = node.borrow();
            (
                n.left_child_node.is_some(),
                n.right_child_node.is_some(),
                n.parent_node.clone(),
                n.left_child_node.clone(),
                n.right_child_node.clone(),
                n.left_child_count,
                n.right_child_count,
            )
        };

        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;

        if has_left && has_right {
            let node_left_rc = node_left.as_ref().unwrap().clone();
            let node_right_rc = node_right.as_ref().unwrap().clone();

            let (candidate, lost_child) = {
                let left_depth = node_left_rc.borrow().depth;
                let right_depth = node_right_rc.borrow().depth;

                if left_depth >= right_depth {
                    node_left_rc.borrow_mut().left_child_count -= 1;
                    let mut cand = node_left_rc.clone();
                    loop {
                        let right_child_opt = cand.borrow().right_child_node.clone();
                        if let Some(right_child) = right_child_opt {
                            cand.borrow_mut().right_child_count -= 1;
                            cand = right_child;
                        } else {
                            break;
                        }
                    }
                    let lost = cand.borrow().left_child_node.clone();
                    (cand, lost)
                } else {
                    node_right_rc.borrow_mut().right_child_count -= 1;
                    let mut cand = node_right_rc.clone();
                    loop {
                        let left_child_opt = cand.borrow().left_child_node.clone();
                        if let Some(left_child) = left_child_opt {
                            cand.borrow_mut().left_child_count -= 1;
                            cand = left_child;
                        } else {
                            break;
                        }
                    }
                    let lost = cand.borrow().right_child_node.clone();
                    (cand, lost)
                }
            };

            let bubble_start = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();

            {
                let mut bs_mut = bubble_start.borrow_mut();
                let is_left = bs_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                if is_left {
                    bs_mut.left_child_node = lost_child.clone();
                } else {
                    bs_mut.right_child_node = lost_child.clone();
                }
            }

            if let Some(ref lost) = lost_child {
                lost.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            if let Some(ref np_weak) = node_parent {
                if let Some(np) = np_weak.upgrade() {
                    let mut np_mut = np.borrow_mut();
                    let is_left = np_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                    if is_left {
                        np_mut.left_child_node = Some(candidate.clone());
                    } else {
                        np_mut.right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                self.root_node = Some(candidate.clone());
            }

            candidate.borrow_mut().parent_node = node_parent.clone();

            {
                let mut cand_mut = candidate.borrow_mut();
                cand_mut.left_child_node = node_left.clone();
                cand_mut.left_child_count = node_left_count;
                cand_mut.right_child_node = node_right.clone();
                cand_mut.right_child_count = node_right_count;
            }

            if let Some(ref lc) = node_left {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref rc) = node_right {
                rc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if !Rc::ptr_eq(&bubble_start, node) {
                let mut cb: Option<Rc<RefCell<BOSNode>>> = Some(bubble_start.clone());
                while let Some(ref cb_rc) = cb {
                    if Rc::ptr_eq(cb_rc, &candidate) {
                        break;
                    }

                    let cb_weak = Rc::downgrade(cb_rc);
                    let cb_copy = cb_rc.clone();

                    {
                        let mut cb_mut = cb_copy.borrow_mut();
                        let left_depth = child_depth(&cb_mut.left_child_node);
                        let right_depth = child_depth(&cb_mut.right_child_node);
                        cb_mut.depth = imax(left_depth, right_depth) as u32;

                        let balance = compute_balance(&cb_mut);
                        if balance > 1 {
                            if let Some(ref rc) = cb_mut.right_child_node {
                                if compute_balance(&rc.borrow()) < 0 {
                                    let rc_copy = rc.clone();
                                    drop(cb_mut);
                                    rotate_right(self, &rc_copy);
                                    cb_mut = cb_copy.borrow_mut();
                                }
                            }
                            let new_root = rotate_left(self, &cb_copy);
                            drop(cb_mut);
                            cb = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        } else if balance < -1 {
                            if let Some(ref lc) = cb_mut.left_child_node {
                                if compute_balance(&lc.borrow()) > 0 {
                                    let lc_copy = lc.clone();
                                    drop(cb_mut);
                                    rotate_left(self, &lc_copy);
                                    cb_mut = cb_copy.borrow_mut();
                                }
                            }
                            let new_root = rotate_right(self, &cb_copy);
                            drop(cb_mut);
                            cb = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                            continue;
                        }
                    }

                    cb = cb_weak.upgrade().and_then(|p| {
                        p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                    });
                }
            }

            {
                let mut cand_mut = candidate.borrow_mut();
                let left_depth = child_depth(&cand_mut.left_child_node);
                let right_depth = child_depth(&cand_mut.right_child_node);
                cand_mut.depth = imax(left_depth, right_depth) as u32;
            }

            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref bu) = bubble_up {
                let mut bu_mut = bu.borrow_mut();
                let is_left = bu_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                if is_left {
                    bu_mut.left_child_count -= 1;
                } else {
                    bu_mut.right_child_count -= 1;
                }
            }
        } else {
            if node_parent.is_none() {
                if has_left {
                    let left_rc = node_left.as_ref().unwrap().clone();
                    self.root_node = Some(left_rc.clone());
                    left_rc.borrow_mut().parent_node = None;
                } else {
                    let right_rc = node_right.as_ref().unwrap().clone();
                    self.root_node = Some(right_rc.clone());
                    right_rc.borrow_mut().parent_node = None;
                }
                bubble_up = None;
            } else {
                let candidate = if has_left { node_left.clone() } else { node_right.clone() };
                let candidate_count = if has_left { node_left_count } else { node_right_count };

                if let Some(ref np_weak) = node_parent {
                    if let Some(np) = np_weak.upgrade() {
                        let mut np_mut = np.borrow_mut();
                        let is_left = np_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                        if is_left {
                            np_mut.left_child_node = candidate.clone();
                            np_mut.left_child_count = candidate_count;
                        } else {
                            np_mut.right_child_node = candidate.clone();
                            np_mut.right_child_count = candidate_count;
                        }
                        if let Some(ref cand) = candidate {
                            cand.borrow_mut().parent_node = Some(Rc::downgrade(&np));
                        }
                    }
                }

                bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
            }
        }

        let mut bubbling_finished = false;
        while let Some(bu) = bubble_up {
            if !bubbling_finished {
                let bu_weak = Rc::downgrade(&bu);
                let bu_rc = bu.clone();

                {
                    let mut bu_mut = bu_rc.borrow_mut();
                    let left_depth = child_depth(&bu_mut.left_child_node);
                    let right_depth = child_depth(&bu_mut.right_child_node);
                    let new_depth = imax(left_depth, right_depth) as u32;
                    let depth_changed = bu_mut.depth != new_depth;
                    bu_mut.depth = new_depth;

                    let balance = compute_balance(&bu_mut);
                    if balance < -1 {
                        if let Some(ref lc) = bu_mut.left_child_node {
                            if compute_balance(&lc.borrow()) > 0 {
                                let lc_copy = lc.clone();
                                drop(bu_mut);
                                rotate_left(self, &lc_copy);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_right(self, &bu_rc);
                    } else if balance > 1 {
                        if let Some(ref rc) = bu_mut.right_child_node {
                            if compute_balance(&rc.borrow()) < 0 {
                                let rc_copy = rc.clone();
                                drop(bu_mut);
                                rotate_right(self, &rc_copy);
                                bu_mut = bu_rc.borrow_mut();
                            }
                        }
                        drop(bu_mut);
                        rotate_left(self, &bu_rc);
                    } else if !depth_changed {
                        bubbling_finished = true;
                    }
                }

                if let Some(ref bu_parent_weak) = bu_rc.borrow().parent_node {
                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
                        let mut parent_mut = bu_parent.borrow_mut();
                        let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu_rc));
                        if is_left {
                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }

                bubble_up = bu_weak.upgrade().and_then(|p| {
                    p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
                });
            } else {
                if let Some(ref bu_parent_weak) = bu.borrow().parent_node {
                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
                        let mut parent_mut = bu_parent.borrow_mut();
                        let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu));
                        if is_left {
                            parent_mut.left_child_count -= 1;
                        } else {
                            parent_mut.right_child_count -= 1;
                        }
                    }
                }
                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;

        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_fn) = self.free_function {
                free_fn(node);
            }
            return None;
        } else if node_mut.weak_ref_node_valid == 1 {
            return Some(node.clone());
        }

        None
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();

        loop {
            match current {
                Some(node) => {
                    let cmp = (self.cmp_function)(key, &node.borrow().key);
                    if cmp == 0 {
                        return Some(node);
                    } else if cmp < 0 {
                        current = node.borrow().left_child_node.clone();
                    } else {
