141	                parent_borrow.right_child_node = Some(r_rc.clone());
142	            }
143	        }
144	    } else {
145	        tree.root_node = Some(r_rc.clone());
146	    }
147	
148	    // Update R's parent
149	    r_rc.borrow_mut().parent_node = p_parent.clone();
150	
151	    // Update P's right child and counts
152	    {
153	        let mut p_mut = p_rc.borrow_mut();
154	        p_mut.right_child_node = r_left;
155	        p_mut.right_child_count = r_left_count;
156	
157	        if let Some(ref rc) = p_mut.right_child_node {
158	            rc.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc));
159	        }
160	
161	        let left_depth = child_depth(&p_mut.left_child_node);
162	        let right_depth = child_depth(&p_mut.right_child_node);
163	        p_mut.depth = imax(left_depth, right_depth) as u32;
164	        p_mut.parent_node = Some(Rc::downgrade(&r_rc));
165	    }
166	
167	    // Update R's left child and counts
168	    {
169	        let mut r_mut = r_rc.borrow_mut();
170	        r_mut.left_child_node = Some(p_rc.clone());
171	
172	        let p_left_count = p_rc.borrow().left_child_count;
173	        let p_right_count = p_rc.borrow().right_child_count;
174	        r_mut.left_child_count = p_left_count + p_right_count + 1;
175	
176	        p_rc.borrow_mut().parent_node = Some(Rc::downgrade(&r_rc));
177	
178	        let left_depth = child_depth(&r_mut.left_child_node);
179	        let right_depth = child_depth(&r_mut.right_child_node);
180	        r_mut.depth = imax(left_depth, right_depth) as u32;
181	    }
182	
183	    r_rc
184	}
