207	    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
208	        if self.root_node.is_none() {
209	            let new_node = Rc::new(RefCell::new(BOSNode {
210	                left_child_count: 0,
211	                right_child_count: 0,
212	                depth: 1,
213	                left_child_node: None,
214	                right_child_node: None,
215	                parent_node: None,
216	                key,
217	                data,
218	                weak_ref_count: 1,
219	                weak_ref_node_valid: 1,
220	            }));
221	            self.root_node = Some(new_node.clone());
222	            return new_node;
223	        }
224	
225	        let mut current = self.root_node.clone().unwrap();
226	        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
227	
228	        loop {
229	            let cmp = (self.cmp_function)(&key, &current.borrow().key);
230	
231	            if cmp < 0 {
232	                let left_count = current.borrow().left_child_count;
233	                let left_opt = current.borrow().left_child_node.clone();
234	                if let Some(next) = left_opt {
235	                    current.borrow_mut().left_child_count = left_count + 1;
236	                    parent = Some(current);
237	                    current = next;
238	                } else {
239	                    current.borrow_mut().left_child_count = left_count + 1;
240	                    let new_node = Rc::new(RefCell::new(BOSNode {
241	                        left_child_count: 0,
242	                        right_child_count: 0,
243	                        depth: 1,
244	                        left_child_node: None,
245	                        right_child_node: None,
246	                        parent_node: Some(Rc::downgrade(&current)),
247	                        key,
248	                        data,
249	                        weak_ref_count: 1,
250	                        weak_ref_node_valid: 1,
251	                    }));
252	                    current.borrow_mut().left_child_node = Some(new_node.clone());
253	                    drop(current.borrow_mut());
254	
255	                    // Rebalance from parent up
256	                    let mut bubble = parent.clone();
257	                    while let Some(ref p) = bubble {
258	                        let p_weak = Rc::downgrade(p);
259	                        let left_depth = child_depth(&p.borrow().left_child_node);
260	                        let right_depth = child_depth(&p.borrow().right_child_node);
261	                        let new_depth = imax(left_depth, right_depth) as u32;
262	                        let depth_changed = p.borrow().depth != new_depth;
263	
264	                        if depth_changed {
265	                            p.borrow_mut().depth = new_depth;
266	                        } else {
267	                            break;
268	                        }
269	
270	                        // Check for AVL violation
271	                        if left_depth - right_depth >= 2 {
272	                            let left = p.borrow().left_child_node.as_ref().unwrap().clone();
273	                            let balance = compute_balance(&left.borrow());
274	                            drop(p.borrow_mut());
275	
276	                            if balance > 0 {
277	                                rotate_left(self, &left);
278	                            }
279	                            let new_root = rotate_right(self, p);
280	                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
281	                            continue;
282	                        }
283	
284	                        if right_depth - left_depth >= 2 {
285	                            let right = p.borrow().right_child_node.as_ref().unwrap().clone();
286	                            let balance = compute_balance(&right.borrow());
287	                            drop(p.borrow_mut());
288	
289	                            if balance < 0 {
290	                                rotate_right(self, &right);
291	                            }
292	                            let new_root = rotate_left(self, p);
293	                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
294	                            continue;
295	                        }
296	
297	                        drop(p.borrow_mut());
298	                        bubble = p_weak.upgrade().and_then(|pp| {
299	                            pp.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
300	                        });
301	                    }
302	                    return new_node;
303	                }
304	            } else {
305	                let right_count = current.borrow().right_child_count;
306	                let right_opt = current.borrow().right_child_node.clone();
307	                if let Some(next) = right_opt {
308	                    current.borrow_mut().right_child_count = right_count + 1;
309	                    parent = Some(current);
310	                    current = next;
311	                } else {
312	                    current.borrow_mut().right_child_count = right_count + 1;
313	                    let new_node = Rc::new(RefCell::new(BOSNode {
314	                        left_child_count: 0,
315	                        right_child_count: 0,
316	                        depth: 1,
317	                        left_child_node: None,
318	                        right_child_node: None,
319	                        parent_node: Some(Rc::downgrade(&current)),
320	                        key,
321	                        data,
322	                        weak_ref_count: 1,
323	                        weak_ref_node_valid: 1,
324	                    }));
325	                    current.borrow_mut().right_child_node = Some(new_node.clone());
326	                    drop(current.borrow_mut());
327	
328	                    // Rebalance from parent up
329	                    let mut bubble = parent.clone();
330	                    while let Some(ref p) = bubble {
331	                        let p_weak = Rc::downgrade(p);
332	                        let left_depth = child_depth(&p.borrow().left_child_node);
333	                        let right_depth = child_depth(&p.borrow().right_child_node);
334	                        let new_depth = imax(left_depth, right_depth) as u32;
335	                        let depth_changed = p.borrow().depth != new_depth;
336	
337	                        if depth_changed {
338	                            p.borrow_mut().depth = new_depth;
339	                        } else {
340	                            break;
341	                        }
342	
343	                        // Check for AVL violation
344	                        if left_depth - right_depth >= 2 {
345	                            let left = p.borrow().left_child_node.as_ref().unwrap().clone();
346	                            let balance = compute_balance(&left.borrow());
347	                            drop(p.borrow_mut());
348	
349	                            if balance > 0 {
350	                                rotate_left(self, &left);
351	                            }
352	                            let new_root = rotate_right(self, p);
353	                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
354	                            continue;
355	                        }
356	
357	                        if right_depth - left_depth >= 2 {
358	                            let right = p.borrow().right_child_node.as_ref().unwrap().clone();
359	                            let balance = compute_balance(&right.borrow());
360	                            drop(p.borrow_mut());
361	
362	                            if balance < 0 {
363	                                rotate_right(self, &right);
364	                            }
365	                            let new_root = rotate_left(self, p);
366	                            bubble = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
367	                            continue;
368	                        }
369	
370	                        drop(p.borrow_mut());
371	                        bubble = p_weak.upgrade().and_then(|pp| {
372	                            pp.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
373	                        });
374	                    }
375	                    return new_node;
376	                }
377	            }
