381	    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
382	        let (has_left, has_right, node_parent, node_left, node_right, node_left_count, node_right_count) = {
383	            let n = node.borrow();
384	            (
385	                n.left_child_node.is_some(),
386	                n.right_child_node.is_some(),
387	                n.parent_node.clone(),
388	                n.left_child_node.clone(),
389	                n.right_child_node.clone(),
390	                n.left_child_count,
391	                n.right_child_count,
392	            )
393	        };
394	
395	        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;
396	
397	        if has_left && has_right {
398	            let node_left_rc = node_left.as_ref().unwrap().clone();
399	            let node_right_rc = node_right.as_ref().unwrap().clone();
400	
401	            let (candidate, lost_child) = {
402	                let left_depth = node_left_rc.borrow().depth;
403	                let right_depth = node_right_rc.borrow().depth;
404	
405	                if left_depth >= right_depth {
406	                    node_left_rc.borrow_mut().left_child_count -= 1;
407	                    let mut cand = node_left_rc.clone();
408	                    loop {
409	                        let right_child_opt = cand.borrow().right_child_node.clone();
410	                        if let Some(right_child) = right_child_opt {
411	                            cand.borrow_mut().right_child_count -= 1;
412	                            cand = right_child;
413	                        } else {
414	                            break;
415	                        }
416	                    }
417	                    let lost = cand.borrow().left_child_node.clone();
418	                    (cand, lost)
419	                } else {
420	                    node_right_rc.borrow_mut().right_child_count -= 1;
421	                    let mut cand = node_right_rc.clone();
422	                    loop {
423	                        let left_child_opt = cand.borrow().left_child_node.clone();
424	                        if let Some(left_child) = left_child_opt {
425	                            cand.borrow_mut().left_child_count -= 1;
426	                            cand = left_child;
427	                        } else {
428	                            break;
429	                        }
430	                    }
431	                    let lost = cand.borrow().right_child_node.clone();
432	                    (cand, lost)
433	                }
434	            };
435	
436	            let bubble_start = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();
437	
438	            {
439	                let mut bs_mut = bubble_start.borrow_mut();
440	                let is_left = bs_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
441	                if is_left {
442	                    bs_mut.left_child_node = lost_child.clone();
443	                } else {
444	                    bs_mut.right_child_node = lost_child.clone();
445	                }
446	            }
447	
448	            if let Some(ref lost) = lost_child {
449	                lost.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
450	            }
451	
452	            if let Some(ref np_weak) = node_parent {
453	                if let Some(np) = np_weak.upgrade() {
454	                    let mut np_mut = np.borrow_mut();
455	                    let is_left = np_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
456	                    if is_left {
457	                        np_mut.left_child_node = Some(candidate.clone());
458	                    } else {
459	                        np_mut.right_child_node = Some(candidate.clone());
460	                    }
461	                }
462	            } else {
463	                self.root_node = Some(candidate.clone());
464	            }
465	
466	            candidate.borrow_mut().parent_node = node_parent.clone();
467	
468	            {
469	                let mut cand_mut = candidate.borrow_mut();
470	                cand_mut.left_child_node = node_left.clone();
471	                cand_mut.left_child_count = node_left_count;
472	                cand_mut.right_child_node = node_right.clone();
473	                cand_mut.right_child_count = node_right_count;
474	            }
475	
476	            if let Some(ref lc) = node_left {
477	                lc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
478	            }
479	            if let Some(ref rc) = node_right {
480	                rc.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
481	            }
482	
483	            if !Rc::ptr_eq(&bubble_start, node) {
484	                let mut cb: Option<Rc<RefCell<BOSNode>>> = Some(bubble_start.clone());
485	                while let Some(ref cb_rc) = cb {
486	                    if Rc::ptr_eq(cb_rc, &candidate) {
487	                        break;
488	                    }
489	
490	                    let cb_weak = Rc::downgrade(cb_rc);
491	                    let cb_copy = cb_rc.clone();
492	
493	                    {
494	                        let mut cb_mut = cb_copy.borrow_mut();
495	                        let left_depth = child_depth(&cb_mut.left_child_node);
496	                        let right_depth = child_depth(&cb_mut.right_child_node);
497	                        cb_mut.depth = imax(left_depth, right_depth) as u32;
498	
499	                        let balance = compute_balance(&cb_mut);
500	                        if balance > 1 {
501	                            if let Some(ref rc) = cb_mut.right_child_node {
502	                                if compute_balance(&rc.borrow()) < 0 {
503	                                    let rc_copy = rc.clone();
504	                                    drop(cb_mut);
505	                                    rotate_right(self, &rc_copy);
506	                                    cb_mut = cb_copy.borrow_mut();
507	                                }
508	                            }
509	                            let new_root = rotate_left(self, &cb_copy);
510	                            drop(cb_mut);
511	                            cb = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
512	                            continue;
513	                        } else if balance < -1 {
514	                            if let Some(ref lc) = cb_mut.left_child_node {
515	                                if compute_balance(&lc.borrow()) > 0 {
516	                                    let lc_copy = lc.clone();
517	                                    drop(cb_mut);
518	                                    rotate_left(self, &lc_copy);
519	                                    cb_mut = cb_copy.borrow_mut();
520	                                }
521	                            }
522	                            let new_root = rotate_right(self, &cb_copy);
523	                            drop(cb_mut);
524	                            cb = new_root.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
525	                            continue;
526	                        }
527	                    }
528	
529	                    cb = cb_weak.upgrade().and_then(|p| {
530	                        p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
531	                    });
532	                }
533	            }
534	
535	            {
536	                let mut cand_mut = candidate.borrow_mut();
537	                let left_depth = child_depth(&cand_mut.left_child_node);
538	                let right_depth = child_depth(&cand_mut.right_child_node);
539	                cand_mut.depth = imax(left_depth, right_depth) as u32;
540	            }
541	
542	            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
543	            if let Some(ref bu) = bubble_up {
544	                let mut bu_mut = bu.borrow_mut();
545	                let is_left = bu_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
546	                if is_left {
547	                    bu_mut.left_child_count -= 1;
548	                } else {
549	                    bu_mut.right_child_count -= 1;
550	                }
551	            }
552	        } else {
553	            if node_parent.is_none() {
554	                if has_left {
555	                    let left_rc = node_left.as_ref().unwrap().clone();
556	                    self.root_node = Some(left_rc.clone());
557	                    left_rc.borrow_mut().parent_node = None;
558	                } else {
559	                    let right_rc = node_right.as_ref().unwrap().clone();
560	                    self.root_node = Some(right_rc.clone());
561	                    right_rc.borrow_mut().parent_node = None;
562	                }
563	                bubble_up = None;
564	            } else {
565	                let candidate = if has_left { node_left.clone() } else { node_right.clone() };
566	                let candidate_count = if has_left { node_left_count } else { node_right_count };
567	
568	                if let Some(ref np_weak) = node_parent {
569	                    if let Some(np) = np_weak.upgrade() {
570	                        let mut np_mut = np.borrow_mut();
571	                        let is_left = np_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
572	                        if is_left {
573	                            np_mut.left_child_node = candidate.clone();
574	                            np_mut.left_child_count = candidate_count;
575	                        } else {
576	                            np_mut.right_child_node = candidate.clone();
577	                            np_mut.right_child_count = candidate_count;
578	                        }
579	                        if let Some(ref cand) = candidate {
580	                            cand.borrow_mut().parent_node = Some(Rc::downgrade(&np));
581	                        }
582	                    }
583	                }
584	
585	                bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
586	            }
587	        }
588	
589	        let mut bubbling_finished = false;
590	        while let Some(bu) = bubble_up {
591	            if !bubbling_finished {
592	                let bu_weak = Rc::downgrade(&bu);
593	                let bu_rc = bu.clone();
594	
595	                {
596	                    let mut bu_mut = bu_rc.borrow_mut();
597	                    let left_depth = child_depth(&bu_mut.left_child_node);
598	                    let right_depth = child_depth(&bu_mut.right_child_node);
599	                    let new_depth = imax(left_depth, right_depth) as u32;
600	                    let depth_changed = bu_mut.depth != new_depth;
601	                    bu_mut.depth = new_depth;
602	
603	                    let balance = compute_balance(&bu_mut);
604	                    if balance < -1 {
605	                        if let Some(ref lc) = bu_mut.left_child_node {
606	                            if compute_balance(&lc.borrow()) > 0 {
607	                                let lc_copy = lc.clone();
608	                                drop(bu_mut);
609	                                rotate_left(self, &lc_copy);
610	                                bu_mut = bu_rc.borrow_mut();
611	                            }
612	                        }
613	                        drop(bu_mut);
614	                        rotate_right(self, &bu_rc);
615	                    } else if balance > 1 {
616	                        if let Some(ref rc) = bu_mut.right_child_node {
617	                            if compute_balance(&rc.borrow()) < 0 {
618	                                let rc_copy = rc.clone();
619	                                drop(bu_mut);
620	                                rotate_right(self, &rc_copy);
621	                                bu_mut = bu_rc.borrow_mut();
622	                            }
623	                        }
624	                        drop(bu_mut);
625	                        rotate_left(self, &bu_rc);
626	                    } else if !depth_changed {
627	                        bubbling_finished = true;
628	                    }
629	                }
630	
631	                if let Some(ref bu_parent_weak) = bu_rc.borrow().parent_node {
632	                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
633	                        let mut parent_mut = bu_parent.borrow_mut();
634	                        let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu_rc));
635	                        if is_left {
636	                            parent_mut.left_child_count -= 1;
637	                        } else {
638	                            parent_mut.right_child_count -= 1;
639	                        }
640	                    }
641	                }
642	
643	                bubble_up = bu_weak.upgrade().and_then(|p| {
644	                    p.borrow().parent_node.as_ref().and_then(|w| w.upgrade())
645	                });
646	            } else {
647	                if let Some(ref bu_parent_weak) = bu.borrow().parent_node {
648	                    if let Some(bu_parent) = bu_parent_weak.upgrade() {
649	                        let mut parent_mut = bu_parent.borrow_mut();
650	                        let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu));
651	                        if is_left {
652	                            parent_mut.left_child_count -= 1;
653	                        } else {
654	                            parent_mut.right_child_count -= 1;
655	                        }
656	                    }
657	                }
658	                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
659	            }
660	        }
661	
662	        node.borrow_mut().weak_ref_node_valid = 0;
663	        self.bostree_node_weak_unref(node);
664	    }
