666	    pub fn bostree_node_weak_unref(
667	        &mut self,
668	        node: &Rc<RefCell<BOSNode>>,
669	    ) -> Option<Rc<RefCell<BOSNode>>> {
670	        let mut node_mut = node.borrow_mut();
671	        node_mut.weak_ref_count -= 1;
672	
673	        if node_mut.weak_ref_count == 0 {
674	            if let Some(ref free_fn) = self.free_function {
675	                free_fn(node);
676	            }
677	            return None;
678	        } else if node_mut.weak_ref_node_valid == 1 {
679	            return Some(node.clone());
680	        }
681	
682	        None
683	    }
