685	    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
686	        let mut current = self.root_node.clone();
687	
688	        loop {
689	            match current {
690	                Some(node) => {
691	                    let cmp = (self.cmp_function)(key, &node.borrow().key);
692	                    if cmp == 0 {
693	                        return Some(node);
694	                    } else if cmp < 0 {
695	                        current = node.borrow().left_child_node.clone();
696	                    } else {
697	                        current = node.borrow().right_child_node.clone();
698	                    }
699	                }
700	                None => return None,
701	            }
702	        }
703	    }
