705	    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
706	        let mut current = self.root_node.clone();
707	
708	        loop {
709	            match current {
710	                Some(node) => {
711	                    let left_count = node.borrow().left_child_count;
712	                    if left_count <= index {
