    }

    fn count_manual(&self) -> u32 {
        fn count_rec(node: &Rc<RefCell<BOSNode>>) -> u32 {
            let left = node.borrow().left_child_node.as_ref().map_or(0, |n| count_rec(n));
            let right = node.borrow().right_child_node.as_ref().map_or(0, |n| count_rec(n));
            left + right + 1
        }
        self.root_node.as_ref().map_or(0, |r| count_rec(r))
    }
