            }
            if let Some(ref right) = n.right_child_node {
                print_rec(right, indent + 1);
            }
        }
        if let Some(ref root) = self.root_node {
            print_rec(root, 0);
        }
    }
}

fn main() {
    let mut tree = BOSTree::bostree_new();

    // Insert A to N (enough to test rotations during removal)
    for c in 'A'..='N' {
        tree.bostree_insert(c.to_string());
    }

    println!("Initial tree with A-N:");
    tree.print_tree();
    println!("count={} manual={}", tree.bostree_node_count(), tree.count_manual());

    // Remove each letter A to N and check counts
    for c in 'A'..='N' {
        if let Some(node) = tree.bostree_lookup(&c.to_string()) {
            tree.bostree_remove(&node);
        }
        let reported = tree.bostree_node_count();
        let manual = tree.count_manual();
        if reported != manual {
            println!("\nAfter removing {}: count={} manual={} MISMATCH!", c, reported, manual);
            tree.print_tree();
            panic!("MISMATCH!");
        } else {
            println!("After removing {}: OK (count={})", c, reported);
        }
    }
    println!("\nAll tests passed!");
}
