// Minimal test - just insert and select
fn main() {
    use std::rc::Rc;
    use std::cell::RefCell;

    type BOSTreeCmpFunction = fn(&str, &str) -> i32;

    #[derive(Debug)]
    pub struct BOSTree {
        root: Option<Rc<RefCell<BOSNode>>>,
        cmp: BOSTreeCmpFunction,
    }

    #[derive(Debug)]
    pub struct BOSNode {
        key: String,
        left: Option<Rc<RefCell<BOSNode>>>,
        right: Option<Rc<RefCell<BOSNode>>>,
        left_count: u32,
        right_count: u32,
    }

    fn tree_new(cmp: BOSTreeCmpFunction) -> BOSTree {
        BOSTree { root: None, cmp }
    }

    fn tree_insert(tree: &mut BOSTree, key: String) {
        let mut current = &mut tree.root;
        let mut parent = None;

        while let Some(ref node) = current {
            parent = Some(node.clone());
            let cmp = (tree.cmp)(&key, &node.borrow().key);
            current = if cmp < 0 {
                node.borrow_mut().left_count += 1;
                &mut node.borrow_mut().left
            } else {
                node.borrow_mut().right_count += 1;
                &mut node.borrow_mut().right
            };
        }

        let mut new_node = Rc::new(RefCell::new(BOSNode {
            key,
            left: None,
            right: None,
            left_count: 0,
            right_count: 0,
        }));
        new_node.borrow_mut().left = None;

        if let Some(p) = parent {
            let cmp = (tree.cmp)(&new_node.borrow().key, &p.borrow().key);
            if cmp < 0 {
                p.borrow_mut().left = Some(new_node);
            } else {
                p.borrow_mut().right = Some(new_node);
            }
        } else {
            tree.root = Some(new_node);
        }
    }

    fn tree_select(tree: &BOSTree, mut index: u32) -> Option<String> {
        let mut current = tree.root.clone();
        while let Some(node) = current {
            let left_count = node.borrow().left_count;
            if index < left_count {
                current = node.borrow().left.clone();
            } else if index == left_count {
                return Some(node.borrow().key.clone());
            } else {
                index = index - left_count - 1;
                current = node.borrow().right.clone();
            }
        }
        None
    }

    fn tree_count(tree: &BOSTree) -> u32 {
        if let Some(ref root) = tree.root {
            let r = root.borrow();
            return r.left_count + r.right_count + 1;
        }
        0
    }

    // Test
    let mut t = tree_new(|a, b| a.cmp(b) as i32);
    for c in "ABCDE".chars() {
        tree_insert(&mut t, c.to_string());
    }

    println!("Tree count: {}", tree_count(&t));
    for i in 0..10 {
        if let Some(k) = tree_select(&t, i) {
            println!("  select({}) = {}", i, k);
        } else {
            break;
        }
    }
}
