        while let Some(bu) = bubble_up {
            let bu_rc = bu.clone();
            let bu_parent = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            // Save which child bu is (before potential rotation)
            let is_left_child = bu_parent.as_ref().map_or(false, |gp| {
                gp.borrow()
                    .left_child_node
                    .as_ref()
                    .map_or(false, |c| Rc::ptr_eq(c, &bu_rc))
            });

            {
                let mut bu_mut = bu_rc.borrow_mut();
                let left_depth = child_depth(&bu_mut.left_child_node);
                let right_depth = child_depth(&bu_mut.right_child_node);
                let new_depth = imax(left_depth, right_depth) as u32;
                bu_mut.depth = new_depth;

                let balance = compute_balance(&bu_mut);
                if balance < -1 {
                    if let Some(ref lc) = bu_mut.left_child_node {
                        if compute_balance(&lc.borrow()) > 0 {
                            let lc_copy = lc.clone();
                            drop(bu_mut);
                            rotate_left(self, &lc_copy);
                            bu_mut = bu_rc.borrow_mut();
                        }
                    }
                    drop(bu_mut);
                    rotate_right(self, &bu_rc);
                } else if balance > 1 {
                    if let Some(ref rc) = bu_mut.right_child_node {
                        if compute_balance(&rc.borrow()) < 0 {
                            let rc_copy = rc.clone();
                            drop(bu_mut);
                            rotate_right(self, &rc_copy);
                            bu_mut = bu_rc.borrow_mut();
                        }
                    }
                    drop(bu_mut);
                    rotate_left(self, &bu_rc);
                }
            }

            // Decrement parent's count for the side containing bu (saved before rotation)
            if let Some(ref gp) = bu_parent {
                let mut gp_mut = gp.borrow_mut();
                if is_left_child {
                    gp_mut.left_child_count = gp_mut.left_child_count.saturating_sub(1);
                } else {
                    gp_mut.right_child_count = gp_mut.right_child_count.saturating_sub(1);
                }
            }

            bubble_up = bu_parent;
