            } else {
                let cand = if has_left { node_left.clone() } else { node_right.clone() };
                if let Some(ref np) = node_parent {
                    if let Some(np_str) = np.upgrade() {
                        let mut npm = np_str.borrow_mut();
                        let is_left = npm.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                        if is_left { npm.left_child_node = cand.clone(); npm.left_child_count = node_left_count; }
                        else { npm.right_child_node = cand.clone(); npm.right_child_count = node_right_count; }
                        if let Some(ref c) = cand { c.borrow_mut().parent_node = Some(Rc::downgrade(&np)); }
                    }
                }
