        }

        // Rebalance up
        while let Some(bu) = bubble_up {
            let bu_rc = bu.clone();
            let bu_parent = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            {
                let mut bum = bu_rc.borrow_mut();
                let ld = child_depth(&bum.left_child_node);
                let rd = child_depth(&bum.right_child_node);
                bum.depth = imax(ld, rd) as u32;
                let bal = compute_balance(&bum);
                if bal < -1 {
                    if let Some(ref lc) = bum.left_child_node {
                        if compute_balance(&lc.borrow()) > 0 {
                            let lc_copy = lc.clone();
                            drop(bum);
                            rotate_left(self, &lc_copy);
