fn imax(i1: i32, i2: i32) -> i32 { if i1 > i2 { i1 } else { i2 } }
fn child_depth(node: &Option<Rc<RefCell<BOSNode>>>) -> i32 {
    node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1)
}
fn compute_balance(node: &BOSNode) -> i32 {
    child_depth(&node.right_child_node) - child_depth(&node.left_child_node)
}

fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = { let mut m = p.borrow_mut(); m.left_child_node.take() };
    let l = match l { Some(l) => l, None => return p.clone() };
    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    let p_parent = p.borrow().parent_node.clone();
    drop(l.borrow());
    let l_rc = l.clone(); let p_rc = p.clone();

    if let Some(ref pw) = p_parent {
        if let Some(pp) = pw.upgrade() {
            let mut pb = pp.borrow_mut();
            let is_left = pb.left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, &p_rc));
            if is_left { pb.left_child_node = Some(l_rc.clone()); }
            else { pb.right_child_node = Some(l_rc.clone()); }
        }
    } else { tree.root_node = Some(l_rc.clone()); }

    l_rc.borrow_mut().parent_node = p_parent.clone();

    {
        let mut pm = p_rc.borrow_mut();
        pm.left_child_node = l_right;
        pm.left_child_count = l_right_count;
        if let Some(ref lc) = pm.left_child_node { lc.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc)); }
        pm.depth = imax(child_depth(&pm.left_child_node), child_depth(&pm.right_child_node)) as u32;
        pm.parent_node = Some(Rc::downgrade(&l_rc));
