        lm.right_child_count = p_rc.borrow().left_child_count + p_rc.borrow().right_child_count + 1;
        p_rc.borrow_mut().parent_node = Some(Rc::downgrade(&l_rc));
        lm.depth = imax(child_depth(&lm.left_child_node), child_depth(&lm.right_child_node)) as u32;
