    }

    fn select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut cur = self.root_node.clone();
        while let Some(n) = cur {
            let lc = n.borrow().left_child_count;
            if index < lc { cur = n.borrow().left_child_node.clone(); }
            else if index == lc { return Some(n); }
            else { index = index - lc - 1; cur = n.borrow().right_child_node.clone(); }
        }
        None
    }
}

fn main() {
    let mut tree = BOSTree::new(|a, b| a.cmp(b) as i32);

    // Insert A-E
    for c in 'A'..='E' {
        tree.insert(c.to_string());
    }

    println!("Initial: count={}", tree.node_count());
    for i in 0..6 {
        if let Some(n) = tree.select(i) { print!("{} ", n.borrow().key); } else { break; }
    }
    println!();

    // Remove C
    if let Some(n) = tree.lookup("C") {
        println!("Removing C");
        tree.remove(&n);
    }

    println!("After removing C: count={}", tree.node_count());
    for i in 0..6 {
        if let Some(n) = tree.select(i) { print!("{} ", n.borrow().key); } else { break; }
    }
    println!();
}
