use Bostree::bostree::*;

fn cmp(a: &str, b: &str) -> i32 {
    a.cmp(b) as i32
}

fn main() {
    let mut tree = BOSTree::bostree_new(cmp, None);

    // Insert just A, B, C
    for c in ['A', 'B', 'C'] {
        let key = c.to_string();
        let _node = tree.bostree_insert(key, None);
    }

    println!("Initial tree count: {}", tree.bostree_node_count());

    // List all nodes
    println!("All nodes in tree:");
    let mut current = tree.bostree_select(0);
    while let Some(n) = current {
        println!("  {}", n.borrow().key);
        current = bostree_next_node(&n);
    }

    // Remove A
    let key = "A".to_string();
    if let Some(node) = tree.bostree_lookup(&key) {
        println!("\nRemoving A...");
        tree.bostree_remove(&node);

        println!("After removing A:");
        println!("  bostree_node_count: {}", tree.bostree_node_count());

        // List all nodes
        println!("All nodes after removal:");
        current = tree.bostree_select(0);
        while let Some(n) = current {
            println!("  {}", n.borrow().key);
            current = bostree_next_node(&n);
        }

        // Check if we can traverse all
        let mut count = 0;
        current = tree.bostree_select(0);
        while let Some(n) = current {
            count += 1;
            current = bostree_next_node(&n);
        }
        println!("  Traversed {} nodes via next_node", count);
    }
}

