use std::cell::RefCell;

fn cmp(a: &str, b: &str) -> i32 {
    a.cmp(b) as i32
}

fn print_node_details(node: &Rc<RefCell<BOSNode>>, indent: &str) {
    let n = node.borrow();
    let parent_key = n.parent_node.as_ref().and_then(|w| w.upgrade()).map(|p| p.borrow().key.clone()).unwrap_or_else(|| "None".to_string());
    println!("{}Node '{}': left_count={}, right_count={}, depth={}, parent={}",
             indent, n.key, n.left_child_count, n.right_child_count, n.depth, parent_key);
}

fn main() {
    let mut tree = BOSTree::bostree_new(cmp, None);

    // Insert A, B, C, D, E
    for c in ['A', 'B', 'C', 'D', 'E'] {
        let key = c.to_string();
        let _node = tree.bostree_insert(key, None);
    }

    println!("Initial tree:");
    if let Some(ref root) = tree.root_node {
        print_node_details(root, "  ");
        if let Some(ref l) = root.borrow().left_child_node {
            print_node_details(l, "    ");
        }
        if let Some(ref r) = root.borrow().right_child_node {
            print_node_details(r, "    ");
        }
    }
    println!("bostree_node_count: {}\n", tree.bostree_node_count());

    // Remove A
    let key = "A".to_string();
    if let Some(node) = tree.bostree_lookup(&key) {
        println!("Removing A...");
        tree.bostree_remove(&node);

        println!("\nAfter removing A:");
        if let Some(ref root) = tree.root_node {
            print_node_details(root, "  ");
            if let Some(ref l) = root.borrow().left_child_node {
                print_node_details(l, "    ");
            }
            if let Some(ref r) = root.borrow().right_child_node {
                print_node_details(r, "    ");
            }
        }
        println!("bostree_node_count: {}", tree.bostree_node_count());

        // Try to get B
        if let Some(b) = tree.bostree_lookup(&"B") {
            println!("\nNode B's parent:");
            if let Some(ref parent) = b.borrow().parent_node {
                if let Some(p) = parent.upgrade() {
                    println!("  B's parent is '{}'", p.borrow().key);
                    println!("  B is left child of parent? {}",
                             p.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &b)));
                }
            } else {
                println!("  B has no parent");
            }
        }

        println!("\nSelect results:");
        for i in 0..6 {
            if let Some(n) = tree.bostree_select(i) {
                println!("  select({}) = {}", i, n.borrow().key);
            } else {
                println!("  select({}) = None", i);
            }
        }

        println!("\nNext node from B:");
        if let Some(b) = tree.bostree_lookup(&"B") {
            if let Some(next) = bostree_next_node(&b) {
                println!("  next of B = {}", next.borrow().key);
            } else {
                println!("  next of B = None");
            }
        }
    }
}"}

