        println!("  Root right: {:?}", root.borrow().right_child_node.as_ref().map(|n| n.borrow().key.clone()));
    }

    // Get node B
    if let Some(b) = tree.bostree_lookup(&"B") {
        println!("\nNode B:");
        println!("  B's right_child_node: {:?}", b.borrow().right_child_node.as_ref().map(|n| n.borrow().key.clone()));

        // Manually trace next_node
        let mut current = b.borrow().right_child_node.clone();
        println!("  Tracing right subtree...");

        while let Some(right) = current {
            println!("    Moving to left child of '{}'", right.borrow().key);
            current = right.borrow().left_child_node.clone();
        }

        println!("  After left traversal, current = {:?}", current.as_ref().map(|n| n.borrow().key.clone()));

        if let Some(n) = current {
            println!("  Returning Some({})", n.borrow().key);
        } else {
            // Walk up
            let mut cur = b.clone();
            loop {
                let parent = cur.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                match parent {
                    Some(p) => {
                        println!("  Parent of '{}' is '{}'", cur.borrow().key, p.borrow().key);
                        if p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) {
                            println!("    '{}' is right child, continue walking up", cur.borrow().key);
                            cur = p;
                        } else {
                            println!("    '{}' is NOT right child, return parent", p.borrow().key);
                            break;
                        }
                    }
                    None => {
                        println!("  No parent, return None");
                        break;
                    }
                }
            }
        }

        // Now test the actual function
        println!("\nTesting bostree_next_node for B:");
        match bostree_next_node(&b) {
            Some(n) => println!("  Result: {}", n.borrow().key),
            None => println!("  Result: None"),
        }
    }

    // Full traversal test
    println!("\nFull traversal test:");
    let mut current = tree.bostree_select(0);
    while let Some(n) = current {
        println!("  Got: {}", n.borrow().key);
        current = bostree_next_node(&n);
    }
}"}

