}

// Manual trace of next_node
fn trace_next(node: &Rc<RefCell<BOSNode>>) {
    let n = node.borrow();
    println!("Node '{}': right_child_node = {:?}, parent = {:?}",
             n.key,
             n.right_child_node.as_ref().map(|r| r.borrow().key.clone()),
             n.parent_node.as_ref().and_then(|w| w.upgrade()).map(|p| p.borrow().key.clone()));

    // Trace right subtree
    let mut current = n.right_child_node.clone();
    let mut path = vec![n.key.clone()];
    while let Some(right) = current {
        path.push(format!("-> left of {}", right.borrow().key));
        current = right.borrow().left_child_node.clone();
    }
    println!("  Right subtree path: {:?}", path);
    println!("  After right traversal, current = {:?}", current.as_ref().map(|c| c.borrow().key.clone()));

    // Walk up
    let mut cur = node.clone();
    let mut up_path = vec![n.key.clone()];
    loop {
        match cur.borrow().parent_node.as_ref() {
            Some(weak) => {
                match weak.upgrade() {
                    Some(p) => {
                        let p_key = p.borrow().key.clone();
                        up_path.push(format!("-> parent {}", p_key));
                        if p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur)) {
                            up_path.push(format!("{} is right child, continue", cur.borrow().key));
                            cur = p;
                        } else {
                            up_path.push(format!("{} is left child, return {}", p_key, p_key));
                            break;
                        }
                    }
                    None => {
                        up_path.push("parent weak ref invalid".to_string());
                        break;
                    }
                }
            }
            None => {
                up_path.push("no parent, return None".to_string());
                break;
            }
        }
    }
    println!("  Walk up path: {:?}", up_path);
}

