pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let mut current = node.borrow().left_child_node.clone();

    while let Some(left) = current {
        current = left.borrow().right_child_node.clone();
    }

    if current.is_some() {
        return current;
    }

    let mut current = node.clone();
    loop {
        let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent {
            Some(p) => {
                if p.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, &current)) {
                    current = p;
                } else {
                    return Some(p);
                }
            }
            None => return None,
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        match parent {
            Some(p) => {
                if p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &current)) {
                    counter += 1 + p.borrow().left_child_count;
                }
                current = p;
            }
            None => return counter,
        }
    }
}

