use std::cell::RefCell;
use std::rc::Rc;

fn cmp(a: &str, b: &str) -> i32 {
    a.cmp(b) as i32
}

// Inline debug version of next_node
fn debug_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    println!("  Input node: {}", node.borrow().key);

    // Step 1: Go right
    let right = node.borrow().right_child_node.clone();
    println!("  Step 1: right_child = {:?}", right.as_ref().map(|n| n.borrow().key.clone()));

    // Step 2: Walk left
    let mut current = right.clone();
    while let Some(right_node) = current {
        println!("  Step 2: Walking left from {}", right_node.borrow().key);
        current = right_node.borrow().left_child_node.clone();
    }
    println!("  Step 2: After walk, current = {:?}", current.as_ref().map(|n| n.borrow().key.clone()));

    if let Some(n) = current {
        println!("  Returning from step 2: Some({})", n.borrow().key);
        return Some(n);
    }

    // Step 3: Walk up
    println!("  Step 3: Walking up...");
    let mut cur = node.clone();
    let mut iterations = 0;

    loop {
        iterations += 1;
        if iterations > 10 {
            println!("  Step 3: Breaking after 10 iterations");
            break;
        }

        println!("    Iteration {}: cur = {}", iterations, cur.borrow().key);

        let parent = {
            let c = cur.borrow();
            c.parent_node.as_ref().and_then(|w| w.upgrade())
        };

        match parent {
            Some(p) => {
                let p_key = p.borrow().key.clone();
                let p_right = p.borrow().right_child_node.as_ref().map(|r| r.borrow().key.clone());
                println!("      parent = {}, right_child = {:?}", p_key, p_right);

                let is_right = p.borrow().right_child_node.as_ref().map_or(false, |r| Rc::ptr_eq(r, &cur));
                println!("      Is '{}' right child of '{}'? {}", cur.borrow().key, p_key, is_right);

                if is_right {
                    println!("      '{}' is right child, continue walking up", cur.borrow().key);
                    cur = p;
                } else {
                    println!("      '{}' is left child, return '{}'", p_key, p_key);
                    return Some(p);
                }
            }
            None => {
                println!("      No parent, return None");
                return None;
            }
        }
    }

    None
}

fn main() {
    let mut tree = BOSTree::bostree_new(cmp, None);

    // Insert 10 nodes
    for c in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'] {
        let key = c.to_string();
        let _node = tree.bostree_insert(key, None);
    }

    // Remove A
    if let Some(node) = tree.bostree_lookup(&"A") {
        tree.bostree_remove(&node);
    }

    // Test various nodes
    for key in ["B", "C", "D", "E", "F", "G", "H", "I", "J"] {
        if let Some(n) = tree.bostree_lookup(key) {
            println!("\n=== next_node('{}') ===", key);
            let result = debug_next_node(&n);
            match result {
                Some(r) => println!("  RESULT: {}", r.borrow().key),
                None => println!("  RESULT: None"),
            }
        }
    }
