use Bostree::bostree::*;
use std::cell::RefCell;
use std::rc::Rc;

fn cmp(a: &str, b: &str) -> i32 {
    a.cmp(b) as i32
}

fn main() {
    let mut tree = BOSTree::bostree_new(cmp, None);

    // Insert one by one and trace
    for c in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J'] {
        let key = c.to_string();
        let _node = tree.bostree_insert(key.clone(), None);

        println!("\n=== After inserting {} ===", c);
        if let Some(ref root) = tree.root_node {
            let r = root.borrow();
            println!("Root: {}, lc={}, rc={}, depth={}",
                     r.key, r.left_child_count, r.right_child_count, r.depth);

            // Check left child
            if let Some(ref lc) = r.left_child_node {
                let lc = lc.borrow();
                println!("  L: {}, lc={}, rc={}", lc.key, lc.left_child_count, lc.right_child_count);
            }
            // Check right child
            if let Some(ref rc) = r.right_child_node {
                let rc = rc.borrow();
                println!("  R: {}, lc={}, rc={}", rc.key, rc.left_child_count, rc.right_child_count);
            }
        }
        println!("Count: {}", tree.bostree_node_count());
    }
}

